    10→---
    11→
    12→# RUC (Recommended Usage Category) System
    13→
    14→This document covers the RUC system, which categorizes assets based on their actual usage compared to planned usage, enabling proactive schedule adjustments.
    15→
    16→## RUC System Overview
    17→
    18→### What is RUC?
    19→
    20→```typescript
    21→interface RUCSystem {
    22→  definition: 'A categorization system for asset usage patterns';
    23→  purpose: 'Identify assets that need schedule adjustments';
    24→
    25→  categories: {
    26→    ACCELERATE: 'Usage higher than planned - schedule maintenance earlier';
    27→    NOMINAL: 'Usage within expected range - no adjustment needed';
    28→    DECELERATE: 'Usage lower than planned - schedule maintenance later';
    29→  };
    30→
    31→  benefits: [
    32→    'Proactive maintenance planning',
    33→    'Reduced maintenance drift',
    34→    'Better resource allocation',
    35→    'Improved asset availability'
    36→  ];
    37→}
    38→```
    39→
    40→### RUC Categories
    41→
    42→```typescript
    43→enum RUCCategory {
    44→  ACCELERATE = 'ACCELERATE',
    45→  NOMINAL = 'NOMINAL',
    46→  DECELERATE = 'DECELERATE'
    47→}
    48→
    49→interface RUCThresholds {
    50→  accelerateThreshold: number;  // e.g., 1.10 (10% above plan)
    51→  decelerateThreshold: number;  // e.g., 0.90 (10% below plan)
    52→
    53→  // Category determined by: actualUsage / plannedUsage
    54→  // > accelerateThreshold -> ACCELERATE
    55→  // < decelerateThreshold -> DECELERATE
    56→  // else -> NOMINAL
    57→}
    58→
    59→const defaultThresholds: RUCThresholds = {
    60→  accelerateThreshold: 1.10,
    61→  decelerateThreshold: 0.90
    62→};
    63→```
    64→
    65→## RUC Calculation
    66→
    67→### Basic Calculation
    68→
    69→```typescript
    70→interface RUCCalculationInput {
    71→  assetId: string;
    72→  currentMileage: number;
    73→  plannedMileage: number;
    74→  calculationDate: Date;
    75→}
    76→
    77→interface RUCResult {
    78→  assetId: string;
    79→  category: RUCCategory;
    80→  ratio: number;
    81→  deviation: number;
    82→  absoluteDeviation: number;
    83→  calculatedAt: Date;
    84→}
    85→
    86→function calculateRUC(
    87→  input: RUCCalculationInput,
    88→  thresholds: RUCThresholds
    89→): RUCResult {
    90→  const ratio = input.currentMileage / input.plannedMileage;
    91→  const deviation = ratio - 1;
    92→  const absoluteDeviation = input.currentMileage - input.plannedMileage;
    93→
    94→  let category: RUCCategory;
    95→
    96→  if (ratio > thresholds.accelerateThreshold) {
    97→    category = RUCCategory.ACCELERATE;
    98→  } else if (ratio < thresholds.decelerateThreshold) {
    99→    category = RUCCategory.DECELERATE;
   100→  } else {
   101→    category = RUCCategory.NOMINAL;
   102→  }
   103→
   104→  return {
   105→    assetId: input.assetId,
   106→    category,
   107→    ratio,
   108→    deviation,
   109→    absoluteDeviation,
   110→    calculatedAt: input.calculationDate
   111→  };
   112→}
   113→```
   114→
   115→### Planned Mileage Calculation
   116→
   117→```typescript
   118→interface PlannedMileageInput {
   119→  assetId: string;
   120→  scheduleStartDate: Date;
   121→  currentDate: Date;
   122→  targetMileageAtScheduleEnd: number;
   123→  scheduleEndDate: Date;
   124→}
   125→
   126→function calculatePlannedMileage(input: PlannedMileageInput): number {
   127→  const totalScheduleDays = daysBetween(
   128→    input.scheduleStartDate,
   129→    input.scheduleEndDate
   130→  );
   131→  const elapsedDays = daysBetween(
   132→    input.scheduleStartDate,
   133→    input.currentDate
   134→  );
   135→
   136→  // Linear interpolation
   137→  const progress = elapsedDays / totalScheduleDays;
   138→  const plannedMileage = input.targetMileageAtScheduleEnd * progress;
   139→
   140→  return Math.round(plannedMileage);
   141→}
   142→
   143→// Alternative: Use baseline from historical data
   144→function calculatePlannedMileageFromBaseline(
   145→  assetId: string,
   146→  baselineDailyRate: number,
   147→  scheduleStartDate: Date,
   148→  currentDate: Date,
   149→  startMileage: number
   150→): number {
   151→  const elapsedDays = daysBetween(scheduleStartDate, currentDate);
   152→  return startMileage + (baselineDailyRate * elapsedDays);
   153→}
   154→```
   155→
   156→### Batch RUC Calculation
   157→
   158→```typescript
   159→interface BatchRUCInput {
   160→  assets: Asset[];
   161→  scheduleEvents: ScheduledEvent[];
   162→  currentDate: Date;
   163→  thresholds: RUCThresholds;
   164→}
   165→
   166→async function calculateBatchRUC(
   167→  input: BatchRUCInput
   168→): Promise<Map<string, RUCResult>> {
   169→  const results = new Map<string, RUCResult>();
   170→
   171→  for (const asset of input.assets) {
   172→    // Find next scheduled event for this asset
   173→    const nextEvent = input.scheduleEvents
   174→      .filter(e => e.assetId === asset.id && e.status === 'scheduled')
   175→      .sort((a, b) => a.scheduledPeriod - b.scheduledPeriod)[0];
   176→
   177→    if (!nextEvent) continue;
   178→
   179→    // Calculate planned mileage at current date
   180→    const plannedMileage = interpolatePlannedMileage(
   181→      asset,
   182→      nextEvent,
   183→      input.currentDate
   184→    );
   185→
   186→    const rucResult = calculateRUC(
   187→      {
   188→        assetId: asset.id,
   189→        currentMileage: asset.currentMileage,
   190→        plannedMileage,
   191→        calculationDate: input.currentDate
   192→      },
   193→      input.thresholds
   194→    );
   195→
   196→    results.set(asset.id, rucResult);
   197→  }
   198→
   199→  return results;
   200→}
   201→```
   202→
   203→## Advanced RUC Models
   204→
   205→### Weighted Moving Average RUC
   206→
   207→```typescript
   208→interface WeightedRUCConfig {
   209→  windowSize: number;  // Number of periods to consider
   210→  weights: number[];   // Weights for each period (recent = higher)
   211→}
   212→
   213→function calculateWeightedRUC(
   214→  historicalRatios: number[],
   215→  config: WeightedRUCConfig,
   216→  thresholds: RUCThresholds
   217→): RUCCategory {
   218→  // Ensure we have enough data
   219→  const ratios = historicalRatios.slice(-config.windowSize);
   220→
   221→  if (ratios.length < config.windowSize) {
   222→    // Pad with 1.0 (nominal) for missing data
   223→    while (ratios.length < config.windowSize) {
   224→      ratios.unshift(1.0);
   225→    }
   226→  }
   227→
   228→  // Normalize weights
   229→  const totalWeight = config.weights.reduce((a, b) => a + b, 0);
   230→  const normalizedWeights = config.weights.map(w => w / totalWeight);
   231→
   232→  // Calculate weighted average
   233→  let weightedSum = 0;
   234→  for (let i = 0; i < config.windowSize; i++) {
   235→    weightedSum += ratios[i] * normalizedWeights[i];
   236→  }
   237→
   238→  if (weightedSum > thresholds.accelerateThreshold) {
   239→    return RUCCategory.ACCELERATE;
   240→  } else if (weightedSum < thresholds.decelerateThreshold) {
   241→    return RUCCategory.DECELERATE;
   242→  }
   243→
   244→  return RUCCategory.NOMINAL;
   245→}
   246→
   247→// Example configuration with exponential weights
   248→const exponentialWeights: WeightedRUCConfig = {
   249→  windowSize: 4,
   250→  weights: [1, 2, 4, 8]  // Most recent period has highest weight
   251→};
   252→```
   253→
   254→### Seasonal RUC Adjustment
   255→
   256→```typescript
   257→interface SeasonalFactor {
   258→  month: number;  // 1-12
   259→  factor: number; // Multiplier (e.g., 1.2 for 20% higher usage)
   260→}
   261→
   262→interface SeasonalRUCConfig {
   263→  baseThresholds: RUCThresholds;
   264→  seasonalFactors: SeasonalFactor[];
   265→}
   266→
   267→function calculateSeasonalRUC(
   268→  currentMileage: number,
   269→  plannedMileage: number,
   270→  currentDate: Date,
   271→  config: SeasonalRUCConfig
   272→): RUCCategory {
   273→  const month = currentDate.getMonth() + 1;
   274→
   275→  // Find seasonal factor for current month
   276→  const seasonalFactor = config.seasonalFactors.find(f => f.month === month);
   277→  const factor = seasonalFactor?.factor ?? 1.0;
   278→
   279→  // Adjust thresholds based on season
   280→  const adjustedThresholds: RUCThresholds = {
   281→    accelerateThreshold: config.baseThresholds.accelerateThreshold * factor,
   282→    decelerateThreshold: config.baseThresholds.decelerateThreshold * factor
   283→  };
   284→
   285→  const ratio = currentMileage / plannedMileage;
   286→
   287→  if (ratio > adjustedThresholds.accelerateThreshold) {
   288→    return RUCCategory.ACCELERATE;
   289→  } else if (ratio < adjustedThresholds.decelerateThreshold) {
   290→    return RUCCategory.DECELERATE;
   291→  }
   292→
   293→  return RUCCategory.NOMINAL;
   294→}
   295→
   296→// Example: Higher thresholds in summer (more usage expected)
   297→const seasonalConfig: SeasonalRUCConfig = {
   298→  baseThresholds: { accelerateThreshold: 1.10, decelerateThreshold: 0.90 },
   299→  seasonalFactors: [
   300→    { month: 6, factor: 1.15 },   // June
   301→    { month: 7, factor: 1.20 },   // July
   302→    { month: 8, factor: 1.15 },   // August
   303→    { month: 12, factor: 0.85 },  // December
   304→    { month: 1, factor: 0.90 }    // January
   305→  ]
   306→};
   307→```
   308→
   309→### Trend-Based RUC
   310→
   311→```typescript
   312→interface TrendRUCResult {
   313→  category: RUCCategory;
   314→  trend: 'increasing' | 'stable' | 'decreasing';
   315→  predictedCategory: RUCCategory;  // Where the asset is heading
   316→  confidence: number;
   317→}
   318→
   319→function calculateTrendRUC(
   320→  historicalRatios: Array<{ date: Date; ratio: number }>,
   321→  thresholds: RUCThresholds
   322→): TrendRUCResult {
   323→  // Sort by date
   324→  const sorted = historicalRatios.sort(
   325→    (a, b) => a.date.getTime() - b.date.getTime()
   326→  );
   327→
   328→  // Current category based on latest ratio
   329→  const currentRatio = sorted[sorted.length - 1].ratio;
   330→  const currentCategory = getRUCCategory(currentRatio, thresholds);
   331→
   332→  // Calculate trend using linear regression
   333→  const n = sorted.length;
   334→  const x = sorted.map((_, i) => i);
   335→  const y = sorted.map(s => s.ratio);
   336→
   337→  const sumX = x.reduce((a, b) => a + b, 0);
   338→  const sumY = y.reduce((a, b) => a + b, 0);
   339→  const sumXY = x.reduce((sum, xi, i) => sum + xi * y[i], 0);
   340→  const sumX2 = x.reduce((sum, xi) => sum + xi * xi, 0);
   341→
   342→  const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);
   343→
   344→  // Determine trend
   345→  let trend: 'increasing' | 'stable' | 'decreasing';
   346→  if (slope > 0.01) {
   347→    trend = 'increasing';
   348→  } else if (slope < -0.01) {
   349→    trend = 'decreasing';
   350→  } else {
   351→    trend = 'stable';
   352→  }
   353→
   354→  // Predict future category (extrapolate 4 periods)
   355→  const predictedRatio = currentRatio + (slope * 4);
   356→  const predictedCategory = getRUCCategory(predictedRatio, thresholds);
   357→
   358→  // Calculate confidence based on R-squared
   359→  const meanY = sumY / n;
   360→  const ssTotal = y.reduce((sum, yi) => sum + Math.pow(yi - meanY, 2), 0);
   361→  const predicted = x.map(xi => meanY + slope * (xi - sumX / n));
   362→  const ssResidual = y.reduce((sum, yi, i) => sum + Math.pow(yi - predicted[i], 2), 0);
   363→  const rSquared = 1 - (ssResidual / ssTotal);
   364→
   365→  return {
   366→    category: currentCategory,
   367→    trend,
   368→    predictedCategory,
   369→    confidence: Math.max(0, Math.min(1, rSquared))
   370→  };
   371→}
   372→```
   373→
   374→## RUC Service Implementation
   375→
   376→### Core Service
   377→
   378→```typescript
   379→// services/ruc.service.ts
   380→export class RUCService {
   381→  constructor(
   382→    private readonly assetRepo: AssetRepository,
   383→    private readonly scheduleRepo: ScheduleRepository,
   384→    private readonly mileageRepo: MileageRepository,
   385→    private readonly rucRepo: RUCRepository
   386→  ) {}
   387→
   388→  async calculateCurrentRUC(
   389→    assetIds?: string[]
   390→  ): Promise<Map<string, RUCResult>> {
   391→    // Get assets
   392→    const assets = assetIds
   393→      ? await this.assetRepo.findByIds(assetIds)
   394→      : await this.assetRepo.findActive();
   395→
   396→    // Get active schedule
   397→    const schedule = await this.scheduleRepo.getPublished();
   398→    if (!schedule) {
   399→      throw new Error('No published schedule found');
   400→    }
   401→
   402→    // Get thresholds from config
   403→    const thresholds = await this.getThresholds();
   404→
   405→    // Calculate RUC for each asset
   406→    const results = await calculateBatchRUC({
   407→      assets,
   408→      scheduleEvents: schedule.events,
   409→      currentDate: new Date(),
   410→      thresholds
   411→    });
   412→
   413→    // Store results
   414→    await this.storeRUCResults(results, schedule.id);
   415→
   416→    return results;
   417→  }
   418→
   419→  async getRUCHistory(
   420→    assetId: string,
   421→    startDate: Date,
   422→    endDate: Date
   423→  ): Promise<RUCResult[]> {
   424→    return this.rucRepo.getHistory(assetId, startDate, endDate);
   425→  }
   426→
   427→  async getRUCDistribution(): Promise<RUCDistribution> {
   428→    const results = await this.calculateCurrentRUC();
   429→
   430→    let accelerate = 0, nominal = 0, decelerate = 0;
   431→
   432→    for (const [, result] of results) {
   433→      switch (result.category) {
   434→        case RUCCategory.ACCELERATE:
   435→          accelerate++;
   436→          break;
   437→        case RUCCategory.NOMINAL:
   438→          nominal++;
   439→          break;
   440→        case RUCCategory.DECELERATE:
   441→          decelerate++;
   442→          break;
   443→      }
   444→    }
   445→
   446→    const total = results.size;
   447→
   448→    return {
   449→      accelerate: { count: accelerate, percentage: accelerate / total },
   450→      nominal: { count: nominal, percentage: nominal / total },
   451→      decelerate: { count: decelerate, percentage: decelerate / total },
   452→      total
   453→    };
   454→  }
   455→
   456→  private async storeRUCResults(
   457→    results: Map<string, RUCResult>,
   458→    scheduleId: string
   459→  ): Promise<void> {
   460→    const records = Array.from(results.values()).map(result => ({
   461→      assetId: result.assetId,
   462→      scheduleId,
   463→      category: result.category,
   464→      ratio: result.ratio,
   465→      deviation: result.deviation,
   466→      absoluteDeviation: result.absoluteDeviation,
   467→      calculatedAt: result.calculatedAt
   468→    }));
   469→
   470→    await this.rucRepo.createBatch(records);
   471→  }
   472→}
   473→```
   474→
   475→### Scheduled RUC Calculation
   476→
   477→```typescript
   478→// jobs/ruc-calculation.job.ts
   479→export class RUCCalculationJob {
   480→  constructor(
   481→    private readonly rucService: RUCService,
   482→    private readonly alertService: AlertService,
   483→    private readonly notificationService: NotificationService
   484→  ) {}
   485→
   486→  @Cron('0 6 * * *')  // Daily at 6 AM
   487→  async runDailyRUCCalculation(): Promise<void> {
   488→    console.log('Starting daily RUC calculation...');
   489→
   490→    try {
   491→      const results = await this.rucService.calculateCurrentRUC();
   492→
   493→      // Check for significant changes
   494→      const alerts = await this.checkForAlerts(results);
   495→
   496→      if (alerts.length > 0) {
   497→        await this.alertService.createBatch(alerts);
   498→        await this.notificationService.sendRUCAlerts(alerts);
   499→      }
   500→
   501→      console.log(`RUC calculation complete. ${results.size} assets processed.`);
   502→    } catch (error) {
   503→      console.error('RUC calculation failed:', error);
   504→      throw error;
   505→    }
   506→  }
   507→
   508→  private async checkForAlerts(
   509→    results: Map<string, RUCResult>
   510→  ): Promise<RUCAlert[]> {
   511→    const alerts: RUCAlert[] = [];
   512→
   513→    // Get previous RUC results for comparison
   514→    const previousResults = await this.rucService.getPreviousResults();
   515→
   516→    for (const [assetId, current] of results) {
   517→      const previous = previousResults.get(assetId);
   518→
   519→      // Alert on category change
   520→      if (previous && previous.category !== current.category) {
   521→        alerts.push({
   522→          type: 'category_change',
   523→          assetId,
   524→          previousCategory: previous.category,
   525→          currentCategory: current.category,
   526→          ratio: current.ratio,
   527→          severity: this.calculateSeverity(previous, current)
   528→        });
   529→      }
   530→
   531→      // Alert on high deviation
   532→      if (Math.abs(current.deviation) > 0.20) {
   533→        alerts.push({
   534→          type: 'high_deviation',
   535→          assetId,
   536→          category: current.category,
   537→          deviation: current.deviation,
   538→          severity: Math.abs(current.deviation) > 0.30 ? 'critical' : 'warning'
   539→        });
   540→      }
   541→    }
   542→
   543→    return alerts;
   544→  }
   545→}
   546→```
   547→
   548→## RUC-Based Schedule Adjustment
   549→
   550→### Automatic Adjustment Rules
   551→
   552→```typescript
   553→interface RUCAdjustmentRule {
   554→  category: RUCCategory;
   555→  minRatio: number;
   556→  maxRatio: number;
   557→  periodAdjustment: number;  // Positive = move later, negative = move earlier
   558→}
   559→
   560→const defaultAdjustmentRules: RUCAdjustmentRule[] = [
   561→  // ACCELERATE: Move maintenance earlier
   562→  { category: RUCCategory.ACCELERATE, minRatio: 1.10, maxRatio: 1.20, periodAdjustment: -1 },
   563→  { category: RUCCategory.ACCELERATE, minRatio: 1.20, maxRatio: 1.30, periodAdjustment: -2 },
   564→  { category: RUCCategory.ACCELERATE, minRatio: 1.30, maxRatio: Infinity, periodAdjustment: -3 },
   565→
   566→  // DECELERATE: Move maintenance later
   567→  { category: RUCCategory.DECELERATE, minRatio: 0.80, maxRatio: 0.90, periodAdjustment: 1 },
   568→  { category: RUCCategory.DECELERATE, minRatio: 0.70, maxRatio: 0.80, periodAdjustment: 2 },
   569→  { category: RUCCategory.DECELERATE, minRatio: 0, maxRatio: 0.70, periodAdjustment: 3 }
   570→];
   571→
   572→function calculateAdjustment(
   573→  rucResult: RUCResult,
   574→  rules: RUCAdjustmentRule[]
   575→): number {
   576→  const applicableRule = rules.find(
   577→    rule => rule.category === rucResult.category &&
   578→            rucResult.ratio >= rule.minRatio &&
   579→            rucResult.ratio < rule.maxRatio
   580→  );
   581→
   582→  return applicableRule?.periodAdjustment ?? 0;
   583→}
   584→```
   585→
   586→### Schedule Adjustment Service
   587→
   588→```typescript
   589→// services/ruc-adjustment.service.ts
   590→export class RUCAdjustmentService {
   591→  async proposeAdjustments(
   592→    scheduleId: string
   593→  ): Promise<ProposedAdjustment[]> {
   594→    const schedule = await this.scheduleRepo.getWithEvents(scheduleId);
   595→    const rucResults = await this.rucService.calculateCurrentRUC();
   596→
   597→    const proposals: ProposedAdjustment[] = [];
   598→
   599→    for (const event of schedule.events) {
   600→      if (event.status !== 'scheduled') continue;
   601→
   602→      const ruc = rucResults.get(event.assetId);
   603→      if (!ruc || ruc.category === RUCCategory.NOMINAL) continue;
   604→
   605→      const adjustment = calculateAdjustment(ruc, defaultAdjustmentRules);
   606→      if (adjustment === 0) continue;
   607→
   608→      const newPeriod = event.scheduledPeriod + adjustment;
   609→
   610→      // Check if adjustment is within allowed window
   611→      if (newPeriod < event.earliestPeriod || newPeriod > event.latestPeriod) {
   612→        continue;  // Cannot adjust outside window
   613→      }
   614→
   615→      proposals.push({
   616→        eventId: event.id,
   617→        assetId: event.assetId,
   618→        currentPeriod: event.scheduledPeriod,
   619→        proposedPeriod: newPeriod,
   620→        rucCategory: ruc.category,
   621→        rucRatio: ruc.ratio,
   622→        adjustment,
   623→        reason: this.generateReason(ruc, adjustment)
   624→      });
   625→    }
   626→
   627→    // Sort by priority (higher deviation = higher priority)
   628→    proposals.sort((a, b) =>
   629→      Math.abs(b.rucRatio - 1) - Math.abs(a.rucRatio - 1)
   630→    );
   631→
   632→    return proposals;
   633→  }
   634→
   635→  async applyAdjustments(
   636→    scheduleId: string,
   637→    adjustmentIds: string[]
   638→  ): Promise<AdjustmentResult> {
   639→    const proposals = await this.proposeAdjustments(scheduleId);
   640→
   641→    const toApply = proposals.filter(p => adjustmentIds.includes(p.eventId));
   642→
   643→    // Validate adjustments don't violate capacity
   644→    const validation = await this.validateAdjustments(scheduleId, toApply);
   645→
   646→    if (!validation.valid) {
   647→      return {
   648→        success: false,
   649→        errors: validation.errors
   650→      };
   651→    }
   652→
   653→    // Apply in transaction
   654→    await this.scheduleRepo.transaction(async (tx) => {
   655→      for (const adj of toApply) {
   656→        await this.scheduleRepo.updateEvent(adj.eventId, {
   657→          scheduledPeriod: adj.proposedPeriod,
   658→          originalPeriod: adj.currentPeriod,
   659→          adjustmentReason: adj.reason,
   660→          adjustmentType: 'ruc_based',
   661→          adjustedAt: new Date()
   662→        }, tx);
   663→      }
   664→    });
   665→
   666→    return {
   667→      success: true,
   668→      adjustedCount: toApply.length
   669→    };
   670→  }
   671→
   672→  private generateReason(ruc: RUCResult, adjustment: number): string {
   673→    const direction = adjustment < 0 ? 'earlier' : 'later';
   674→    const deviation = ((ruc.ratio - 1) * 100).toFixed(1);
   675→
   676→    return `RUC ${ruc.category}: Asset usage ${deviation}% ` +
   677→           `${ruc.ratio > 1 ? 'above' : 'below'} plan. ` +
   678→           `Moving maintenance ${Math.abs(adjustment)} period(s) ${direction}.`;
   679→  }
   680→}
   681→```
