# RUC (Recommended Usage Category) System

This document covers the RUC system, which categorizes assets based on their actual usage compared to planned usage, enabling proactive schedule adjustments.

## RUC System Overview

### What is RUC?

```typescript
interface RUCSystem {
  definition: 'A categorization system for asset usage patterns';
  purpose: 'Identify assets that need schedule adjustments';

  categories: {
    ACCELERATE: 'Usage higher than planned - schedule maintenance earlier';
    NOMINAL: 'Usage within expected range - no adjustment needed';
    DECELERATE: 'Usage lower than planned - schedule maintenance later';
  };

  benefits: [
    'Proactive maintenance planning',
    'Reduced maintenance drift',
    'Better resource allocation',
    'Improved asset availability'
  ];
}
```

### RUC Categories

```typescript
enum RUCCategory {
  ACCELERATE = 'ACCELERATE',
  NOMINAL = 'NOMINAL',
  DECELERATE = 'DECELERATE'
}

interface RUCThresholds {
  accelerateThreshold: number;  // e.g., 1.10 (10% above plan)
  decelerateThreshold: number;  // e.g., 0.90 (10% below plan)

  // Category determined by: actualUsage / plannedUsage
  // > accelerateThreshold -> ACCELERATE
  // < decelerateThreshold -> DECELERATE
  // else -> NOMINAL
}

const defaultThresholds: RUCThresholds = {
  accelerateThreshold: 1.10,
  decelerateThreshold: 0.90
};
```

## RUC Calculation

### Basic Calculation

```typescript
interface RUCCalculationInput {
  assetId: string;
  currentMileage: number;
  plannedMileage: number;
  calculationDate: Date;
}

interface RUCResult {
  assetId: string;
  category: RUCCategory;
  ratio: number;
  deviation: number;
  absoluteDeviation: number;
  calculatedAt: Date;
}

function calculateRUC(
  input: RUCCalculationInput,
  thresholds: RUCThresholds
): RUCResult {
  const ratio = input.currentMileage / input.plannedMileage;
  const deviation = ratio - 1;
  const absoluteDeviation = input.currentMileage - input.plannedMileage;

  let category: RUCCategory;

  if (ratio > thresholds.accelerateThreshold) {
    category = RUCCategory.ACCELERATE;
  } else if (ratio < thresholds.decelerateThreshold) {
    category = RUCCategory.DECELERATE;
  } else {
    category = RUCCategory.NOMINAL;
  }

  return {
    assetId: input.assetId,
    category,
    ratio,
    deviation,
    absoluteDeviation,
    calculatedAt: input.calculationDate
  };
}
```

### Planned Mileage Calculation

```typescript
interface PlannedMileageInput {
  assetId: string;
  scheduleStartDate: Date;
  currentDate: Date;
  targetMileageAtScheduleEnd: number;
  scheduleEndDate: Date;
}

function calculatePlannedMileage(input: PlannedMileageInput): number {
  const totalScheduleDays = daysBetween(
    input.scheduleStartDate,
    input.scheduleEndDate
  );
  const elapsedDays = daysBetween(
    input.scheduleStartDate,
    input.currentDate
  );

  // Linear interpolation
  const progress = elapsedDays / totalScheduleDays;
  const plannedMileage = input.targetMileageAtScheduleEnd * progress;

  return Math.round(plannedMileage);
}

// Alternative: Use baseline from historical data
function calculatePlannedMileageFromBaseline(
  assetId: string,
  baselineDailyRate: number,
  scheduleStartDate: Date,
  currentDate: Date,
  startMileage: number
): number {
  const elapsedDays = daysBetween(scheduleStartDate, currentDate);
  return startMileage + (baselineDailyRate * elapsedDays);
}
```

### Batch RUC Calculation

```typescript
interface BatchRUCInput {
  assets: Asset[];
  scheduleEvents: ScheduledEvent[];
  currentDate: Date;
  thresholds: RUCThresholds;
}

async function calculateBatchRUC(
  input: BatchRUCInput
): Promise<Map<string, RUCResult>> {
  const results = new Map<string, RUCResult>();

  for (const asset of input.assets) {
    // Find next scheduled event for this asset
    const nextEvent = input.scheduleEvents
      .filter(e => e.assetId === asset.id && e.status === 'scheduled')
      .sort((a, b) => a.scheduledPeriod - b.scheduledPeriod)[0];

    if (!nextEvent) continue;

    // Calculate planned mileage at current date
    const plannedMileage = interpolatePlannedMileage(
      asset,
      nextEvent,
      input.currentDate
    );

    const rucResult = calculateRUC(
      {
        assetId: asset.id,
        currentMileage: asset.currentMileage,
        plannedMileage,
        calculationDate: input.currentDate
      },
      input.thresholds
    );

    results.set(asset.id, rucResult);
  }

  return results;
}
```

## Advanced RUC Models

### Weighted Moving Average RUC

```typescript
interface WeightedRUCConfig {
  windowSize: number;  // Number of periods to consider
  weights: number[];   // Weights for each period (recent = higher)
}

function calculateWeightedRUC(
  historicalRatios: number[],
  config: WeightedRUCConfig,
  thresholds: RUCThresholds
): RUCCategory {
  // Ensure we have enough data
  const ratios = historicalRatios.slice(-config.windowSize);

  if (ratios.length < config.windowSize) {
    // Pad with 1.0 (nominal) for missing data
    while (ratios.length < config.windowSize) {
      ratios.unshift(1.0);
    }
  }

  // Normalize weights
  const totalWeight = config.weights.reduce((a, b) => a + b, 0);
  const normalizedWeights = config.weights.map(w => w / totalWeight);

  // Calculate weighted average
  let weightedSum = 0;
  for (let i = 0; i < config.windowSize; i++) {
    weightedSum += ratios[i] * normalizedWeights[i];
  }

  if (weightedSum > thresholds.accelerateThreshold) {
    return RUCCategory.ACCELERATE;
  } else if (weightedSum < thresholds.decelerateThreshold) {
    return RUCCategory.DECELERATE;
  }

  return RUCCategory.NOMINAL;
}

// Example configuration with exponential weights
