### Seasonal RUC Adjustment

```typescript
interface SeasonalFactor {
  month: number;  // 1-12
  factor: number; // Multiplier (e.g., 1.2 for 20% higher usage)
}

interface SeasonalRUCConfig {
  baseThresholds: RUCThresholds;
  seasonalFactors: SeasonalFactor[];
}

function calculateSeasonalRUC(
  currentMileage: number,
  plannedMileage: number,
  currentDate: Date,
  config: SeasonalRUCConfig
): RUCCategory {
  const month = currentDate.getMonth() + 1;

  // Find seasonal factor for current month
  const seasonalFactor = config.seasonalFactors.find(f => f.month === month);
  const factor = seasonalFactor?.factor ?? 1.0;

  // Adjust thresholds based on season
  const adjustedThresholds: RUCThresholds = {
    accelerateThreshold: config.baseThresholds.accelerateThreshold * factor,
    decelerateThreshold: config.baseThresholds.decelerateThreshold * factor
  };

  const ratio = currentMileage / plannedMileage;

  if (ratio > adjustedThresholds.accelerateThreshold) {
    return RUCCategory.ACCELERATE;
  } else if (ratio < adjustedThresholds.decelerateThreshold) {
    return RUCCategory.DECELERATE;
  }

  return RUCCategory.NOMINAL;
}

// Example: Higher thresholds in summer (more usage expected)
const seasonalConfig: SeasonalRUCConfig = {
  baseThresholds: { accelerateThreshold: 1.10, decelerateThreshold: 0.90 },
  seasonalFactors: [
    { month: 6, factor: 1.15 },   // June
    { month: 7, factor: 1.20 },   // July
    { month: 8, factor: 1.15 },   // August
    { month: 12, factor: 0.85 },  // December
    { month: 1, factor: 0.90 }    // January
  ]
};
```

### Trend-Based RUC

```typescript
interface TrendRUCResult {
  category: RUCCategory;
  trend: 'increasing' | 'stable' | 'decreasing';
  predictedCategory: RUCCategory;  // Where the asset is heading
  confidence: number;
}

function calculateTrendRUC(
  historicalRatios: Array<{ date: Date; ratio: number }>,
  thresholds: RUCThresholds
): TrendRUCResult {
  // Sort by date
  const sorted = historicalRatios.sort(
    (a, b) => a.date.getTime() - b.date.getTime()
  );

  // Current category based on latest ratio
  const currentRatio = sorted[sorted.length - 1].ratio;
  const currentCategory = getRUCCategory(currentRatio, thresholds);

  // Calculate trend using linear regression
  const n = sorted.length;
  const x = sorted.map((_, i) => i);
  const y = sorted.map(s => s.ratio);

  const sumX = x.reduce((a, b) => a + b, 0);
  const sumY = y.reduce((a, b) => a + b, 0);
  const sumXY = x.reduce((sum, xi, i) => sum + xi * y[i], 0);
  const sumX2 = x.reduce((sum, xi) => sum + xi * xi, 0);

  const slope = (n * sumXY - sumX * sumY) / (n * sumX2 - sumX * sumX);

  // Determine trend
  let trend: 'increasing' | 'stable' | 'decreasing';
  if (slope > 0.01) {
    trend = 'increasing';
  } else if (slope < -0.01) {
    trend = 'decreasing';
  } else {
    trend = 'stable';
  }

  // Predict future category (extrapolate 4 periods)
  const predictedRatio = currentRatio + (slope * 4);
  const predictedCategory = getRUCCategory(predictedRatio, thresholds);

  // Calculate confidence based on R-squared
  const meanY = sumY / n;
  const ssTotal = y.reduce((sum, yi) => sum + Math.pow(yi - meanY, 2), 0);
  const predicted = x.map(xi => meanY + slope * (xi - sumX / n));
  const ssResidual = y.reduce((sum, yi, i) => sum + Math.pow(yi - predicted[i], 2), 0);
  const rSquared = 1 - (ssResidual / ssTotal);

  return {
    category: currentCategory,
    trend,
    predictedCategory,
    confidence: Math.max(0, Math.min(1, rSquared))
  };
}
```

## RUC Service Implementation

### Core Service

```typescript
// services/ruc.service.ts
export class RUCService {
  constructor(
    private readonly assetRepo: AssetRepository,
    private readonly scheduleRepo: ScheduleRepository,
    private readonly mileageRepo: MileageRepository,
    private readonly rucRepo: RUCRepository
  ) {}

  async calculateCurrentRUC(
    assetIds?: string[]
  ): Promise<Map<string, RUCResult>> {
    // Get assets
    const assets = assetIds
      ? await this.assetRepo.findByIds(assetIds)
      : await this.assetRepo.findActive();

    // Get active schedule
    const schedule = await this.scheduleRepo.getPublished();
    if (!schedule) {
      throw new Error('No published schedule found');
    }

    // Get thresholds from config
    const thresholds = await this.getThresholds();

    // Calculate RUC for each asset
    const results = await calculateBatchRUC({
      assets,
      scheduleEvents: schedule.events,
      currentDate: new Date(),
      thresholds
    });

    // Store results
    await this.storeRUCResults(results, schedule.id);

    return results;
  }

  async getRUCHistory(
    assetId: string,
    startDate: Date,
    endDate: Date
  ): Promise<RUCResult[]> {
    return this.rucRepo.getHistory(assetId, startDate, endDate);
  }

  async getRUCDistribution(): Promise<RUCDistribution> {
    const results = await this.calculateCurrentRUC();

    let accelerate = 0, nominal = 0, decelerate = 0;

    for (const [, result] of results) {
      switch (result.category) {
        case RUCCategory.ACCELERATE:
          accelerate++;
          break;
        case RUCCategory.NOMINAL:
          nominal++;
          break;
        case RUCCategory.DECELERATE:
          decelerate++;
          break;
      }
    }

    const total = results.size;

    return {
      accelerate: { count: accelerate, percentage: accelerate / total },
      nominal: { count: nominal, percentage: nominal / total },
      decelerate: { count: decelerate, percentage: decelerate / total },
      total
    };
  }

  private async storeRUCResults(
    results: Map<string, RUCResult>,
    scheduleId: string
  ): Promise<void> {
    const records = Array.from(results.values()).map(result => ({
      assetId: result.assetId,
      scheduleId,
      category: result.category,
      ratio: result.ratio,
      deviation: result.deviation,
      absoluteDeviation: result.absoluteDeviation,
      calculatedAt: result.calculatedAt
    }));

    await this.rucRepo.createBatch(records);
  }
}
```

### Scheduled RUC Calculation

```typescript
// jobs/ruc-calculation.job.ts
export class RUCCalculationJob {
  constructor(
    private readonly rucService: RUCService,
    private readonly alertService: AlertService,
    private readonly notificationService: NotificationService
  ) {}

  @Cron('0 6 * * *')  // Daily at 6 AM
  async runDailyRUCCalculation(): Promise<void> {
    console.log('Starting daily RUC calculation...');

    try {
      const results = await this.rucService.calculateCurrentRUC();

      // Check for significant changes
      const alerts = await this.checkForAlerts(results);

      if (alerts.length > 0) {
        await this.alertService.createBatch(alerts);
        await this.notificationService.sendRUCAlerts(alerts);
      }

      console.log(`RUC calculation complete. ${results.size} assets processed.`);
    } catch (error) {
      console.error('RUC calculation failed:', error);
      throw error;
    }
  }

  private async checkForAlerts(
    results: Map<string, RUCResult>
  ): Promise<RUCAlert[]> {
    const alerts: RUCAlert[] = [];

    // Get previous RUC results for comparison
    const previousResults = await this.rucService.getPreviousResults();

    for (const [assetId, current] of results) {
      const previous = previousResults.get(assetId);

      // Alert on category change
      if (previous && previous.category !== current.category) {
        alerts.push({
          type: 'category_change',
          assetId,
          previousCategory: previous.category,
          currentCategory: current.category,
          ratio: current.ratio,
          severity: this.calculateSeverity(previous, current)
        });
      }

      // Alert on high deviation
      if (Math.abs(current.deviation) > 0.20) {
        alerts.push({
          type: 'high_deviation',
          assetId,
          category: current.category,
          deviation: current.deviation,
          severity: Math.abs(current.deviation) > 0.30 ? 'critical' : 'warning'
        });
      }
    }

    return alerts;
  }
}
