### Integration Pattern

```typescript
// TypeScript calls Python solver via subprocess
import { spawn } from 'bun';

interface SolverInput {
  events: MaintenanceEvent[];
  periods: number[];
  capacity: number;
  timeLimit: number;
}

interface SolverOutput {
  status: string;
  schedule: Record<string, number>;
  objective: number;
  solveTime: number;
}

async function callSolver(input: SolverInput): Promise<SolverOutput> {
  const proc = spawn(['python3', 'solver/main.py'], {
    stdin: 'pipe',
    stdout: 'pipe',
    stderr: 'pipe'
  });

  // Send input
  proc.stdin.write(JSON.stringify(input));
  proc.stdin.end();

  // Read output
  const stdout = await new Response(proc.stdout).text();
  const stderr = await new Response(proc.stderr).text();

  const exitCode = await proc.exited;
  if (exitCode !== 0) {
    throw new Error(`Solver failed: ${stderr}`);
  }

  return JSON.parse(stdout);
}
```

