    11→
    12→# What-If Simulations
    13→
    14→This document covers what-if simulation features for fleet maintenance scheduling, enabling planners to explore alternative scenarios and their impacts.
    15→
    16→## What-If Simulation Overview
    17→
    18→### Purpose
    19→
    20→```typescript
    21→interface WhatIfSimulation {
    22→  definition: 'Tool for exploring hypothetical scheduling scenarios';
    23→
    24→  useCases: [
    25→    'Impact of adding/removing assets from fleet',
    26→    'Effect of changing maintenance intervals',
    27→    'Resource capacity adjustments',
    28→    'Seasonal demand variations',
    29→    'Budget constraint analysis',
    30→    'Risk assessment'
    31→  ];
    32→
    33→  benefits: [
    34→    'Better decision making',
    35→    'Risk identification',
    36→    'Resource optimization',
    37→    'Stakeholder communication',
    38→    'Contingency planning'
    39→  ];
    40→}
    41→```
    42→
    43→### Simulation Types
    44→
    45→```typescript
    46→type SimulationType =
    47→  | 'fleet_change'           // Add/remove assets
    48→  | 'interval_change'        // Modify maintenance intervals
    49→  | 'capacity_change'        // Adjust resource capacity
    50→  | 'demand_change'          // Change usage patterns
    51→  | 'constraint_change'      // Modify constraints
    52→  | 'multi_scenario';        // Combine multiple changes
    53→
    54→interface SimulationScenario {
    55→  id: string;
    56→  name: string;
    57→  description: string;
    58→  type: SimulationType;
    59→  baselineScheduleId: string;
    60→  changes: ScenarioChange[];
    61→  createdAt: Date;
    62→  createdBy: string;
    63→}
    64→```
    65→
    66→## Scenario Definition
    67→
    68→### Change Types
    69→
    70→```typescript
    71→interface ScenarioChange {
    72→  type: ChangeType;
    73→  target: ChangeTarget;
    74→  parameters: ChangeParameters;
    75→}
    76→
    77→type ChangeType =
    78→  | 'add'
    79→  | 'remove'
    80→  | 'modify'
    81→  | 'replace';
    82→
    83→interface ChangeTarget {
    84→  entityType: 'asset' | 'maintenance_type' | 'resource' | 'constraint';
    85→  entityId?: string;
    86→  filter?: TargetFilter;  // Apply to multiple entities
    87→}
    88→
    89→interface TargetFilter {
    90→  assetType?: string;
    91→  maintenanceCode?: string;
    92→  fleetId?: string;
    93→}
    94→
    95→// Example change parameters by type
    96→interface FleetChangeParams {
    97→  assets: AssetDefinition[];
    98→  effectiveDate: Date;
    99→}
   100→
   101→interface IntervalChangeParams {
   102→  maintenanceTypeId: string;
   103→  newIntervalMileage?: number;
   104→  newIntervalDays?: number;
   105→  changePercentage?: number;  // Alternative: change by percentage
   106→}
   107→
   108→interface CapacityChangeParams {
   109→  resourceId: string;
   110→  newCapacity?: number;
   111→  capacityMultiplier?: number;
   112→  periodRange?: { start: number; end: number };
   113→}
   114→
   115→interface DemandChangeParams {
   116→  assetIds?: string[];
   117→  usageMultiplier: number;
   118→  seasonalPattern?: SeasonalPattern;
   119→}
   120→```
   121→
   122→### Scenario Builder
   123→
   124→```typescript
   125→class ScenarioBuilder {
   126→  private changes: ScenarioChange[] = [];
   127→  private name: string = '';
   128→  private description: string = '';
   129→
   130→  constructor(
   131→    private baselineScheduleId: string
   132→  ) {}
   133→
   134→  withName(name: string): this {
   135→    this.name = name;
   136→    return this;
   137→  }
   138→
   139→  withDescription(description: string): this {
   140→    this.description = description;
   141→    return this;
   142→  }
   143→
   144→  addAssets(assets: AssetDefinition[]): this {
   145→    this.changes.push({
   146→      type: 'add',
   147→      target: { entityType: 'asset' },
   148→      parameters: { assets, effectiveDate: new Date() }
   149→    });
   150→    return this;
   151→  }
   152→
   153→  removeAssets(assetIds: string[]): this {
   154→    for (const assetId of assetIds) {
   155→      this.changes.push({
   156→        type: 'remove',
   157→        target: { entityType: 'asset', entityId: assetId },
   158→        parameters: {}
   159→      });
   160→    }
   161→    return this;
   162→  }
   163→
   164→  modifyInterval(
   165→    maintenanceTypeId: string,
   166→    changePercentage: number
   167→  ): this {
   168→    this.changes.push({
   169→      type: 'modify',
   170→      target: { entityType: 'maintenance_type', entityId: maintenanceTypeId },
   171→      parameters: { changePercentage }
   172→    });
   173→    return this;
   174→  }
   175→
   176→  adjustCapacity(
   177→    resourceId: string,
   178→    multiplier: number,
   179→    periods?: { start: number; end: number }
   180→  ): this {
   181→    this.changes.push({
   182→      type: 'modify',
   183→      target: { entityType: 'resource', entityId: resourceId },
   184→      parameters: {
   185→        capacityMultiplier: multiplier,
   186→        periodRange: periods
   187→      }
   188→    });
   189→    return this;
   190→  }
   191→
   192→  changeUsagePattern(
   193→    multiplier: number,
   194→    assetFilter?: TargetFilter
   195→  ): this {
   196→    this.changes.push({
   197→      type: 'modify',
   198→      target: {
   199→        entityType: 'asset',
   200→        filter: assetFilter
   201→      },
   202→      parameters: { usageMultiplier: multiplier }
   203→    });
   204→    return this;
   205→  }
   206→
   207→  build(): SimulationScenario {
   208→    return {
   209→      id: crypto.randomUUID(),
   210→      name: this.name,
   211→      description: this.description,
   212→      type: this.determineType(),
   213→      baselineScheduleId: this.baselineScheduleId,
   214→      changes: this.changes,
   215→      createdAt: new Date(),
   216→      createdBy: ''  // Set by service
   217→    };
   218→  }
   219→
   220→  private determineType(): SimulationType {
   221→    if (this.changes.length > 1) {
   222→      const types = new Set(this.changes.map(c => c.target.entityType));
   223→      if (types.size > 1) return 'multi_scenario';
   224→    }
   225→
   226→    const firstChange = this.changes[0];
   227→    switch (firstChange?.target.entityType) {
   228→      case 'asset': return 'fleet_change';
   229→      case 'maintenance_type': return 'interval_change';
   230→      case 'resource': return 'capacity_change';
   231→      default: return 'constraint_change';
   232→    }
   233→  }
   234→}
   235→
   236→// Usage example
   237→const scenario = new ScenarioBuilder('schedule-123')
   238→  .withName('Fleet Expansion 2025')
   239→  .withDescription('Adding 10 new vehicles in Q1 2025')
   240→  .addAssets(newVehicles)
   241→  .adjustCapacity('technician-hours', 1.2)
   242→  .build();
   243→```
   244→
   245→## Simulation Engine
   246→
   247→### Core Engine
   248→
   249→```typescript
   250→// services/simulation-engine.service.ts
   251→export class SimulationEngine {
   252→  constructor(
   253→    private readonly scheduleRepo: ScheduleRepository,
   254→    private readonly solverService: SolverService,
   255→    private readonly forecastService: ForecastService
   256→  ) {}
   257→
   258→  async runSimulation(
   259→    scenario: SimulationScenario
   260→  ): Promise<SimulationResult> {
   261→    // 1. Load baseline
   262→    const baseline = await this.scheduleRepo.getWithEvents(
   263→      scenario.baselineScheduleId
   264→    );
   265→
   266→    // 2. Create modified input data
   267→    const modifiedInput = await this.applyChanges(baseline, scenario.changes);
   268→
   269→    // 3. Run optimization with modified data
   270→    const simulatedSchedule = await this.solverService.solve(modifiedInput);
   271→
   272→    // 4. Compare results
   273→    const comparison = this.compareSchedules(baseline, simulatedSchedule);
   274→
   275→    // 5. Calculate impacts
   276→    const impacts = this.calculateImpacts(baseline, simulatedSchedule, scenario);
   277→
   278→    return {
   279→      scenarioId: scenario.id,
   280→      baselineScheduleId: baseline.id,
   281→      simulatedSchedule,
   282→      comparison,
   283→      impacts,
   284→      executedAt: new Date()
   285→    };
   286→  }
   287→
   288→  private async applyChanges(
   289→    baseline: Schedule,
   290→    changes: ScenarioChange[]
   291→  ): Promise<SolverInput> {
   292→    let assets = [...baseline.assets];
   293→    let maintenanceTypes = [...baseline.maintenanceTypes];
   294→    let capacity = { ...baseline.capacity };
   295→    let forecasts = [...baseline.forecasts];
   296→
   297→    for (const change of changes) {
   298→      switch (change.target.entityType) {
   299→        case 'asset':
   300→          ({ assets, forecasts } = this.applyAssetChange(
   301→            assets, forecasts, change
   302→          ));
   303→          break;
   304→
   305→        case 'maintenance_type':
   306→          maintenanceTypes = this.applyMaintenanceChange(
   307→            maintenanceTypes, change
   308→          );
   309→          break;
   310→
   311→        case 'resource':
   312→          capacity = this.applyCapacityChange(capacity, change);
   313→          break;
   314→      }
   315→    }
   316→
   317→    // Regenerate events based on modified data
   318→    const events = await this.generateEvents(
   319→      assets,
   320→      maintenanceTypes,
   321→      forecasts,
   322→      baseline.periods.length
   323→    );
   324→
   325→    return {
   326→      events,
   327→      num_periods: baseline.periods.length,
   328→      capacity,
   329→      config: baseline.solverConfig
   330→    };
   331→  }
   332→
   333→  private applyAssetChange(
   334→    assets: Asset[],
   335→    forecasts: MileageForecast[],
   336→    change: ScenarioChange
   337→  ): { assets: Asset[]; forecasts: MileageForecast[] } {
   338→    if (change.type === 'add') {
   339→      const params = change.parameters as FleetChangeParams;
   340→      const newAssets = params.assets;
   341→
   342→      // Generate forecasts for new assets
   343→      const newForecasts = newAssets.flatMap(asset =>
   344→        this.forecastService.generateLinearForecast(asset, params.effectiveDate)
   345→      );
   346→
   347→      return {
   348→        assets: [...assets, ...newAssets],
   349→        forecasts: [...forecasts, ...newForecasts]
   350→      };
   351→    }
   352→
   353→    if (change.type === 'remove') {
   354→      const assetId = change.target.entityId!;
   355→      return {
   356→        assets: assets.filter(a => a.id !== assetId),
   357→        forecasts: forecasts.filter(f => f.assetId !== assetId)
   358→      };
   359→    }
   360→
   361→    if (change.type === 'modify' && change.parameters.usageMultiplier) {
   362→      const multiplier = change.parameters.usageMultiplier;
   363→      const filter = change.target.filter;
   364→
   365→      const affectedIds = assets
   366→        .filter(a => !filter || this.matchesFilter(a, filter))
   367→        .map(a => a.id);
   368→
   369→      return {
   370→        assets,
   371→        forecasts: forecasts.map(f => {
   372→          if (affectedIds.includes(f.assetId)) {
   373→            return {
   374→              ...f,
   375→              projectedMileage: Math.round(f.projectedMileage * multiplier)
   376→            };
   377→          }
   378→          return f;
   379→        })
   380→      };
   381→    }
   382→
   383→    return { assets, forecasts };
   384→  }
   385→
   386→  private compareSchedules(
   387→    baseline: Schedule,
   388→    simulated: Schedule
   389→  ): ScheduleComparison {
   390→    return {
   391→      totalEvents: {
   392→        baseline: baseline.events.length,
   393→        simulated: simulated.events.length,
   394→        difference: simulated.events.length - baseline.events.length
   395→      },
   396→      peakWorkload: {
   397→        baseline: baseline.metrics.peakWorkload,
   398→        simulated: simulated.metrics.peakWorkload,
   399→        difference: simulated.metrics.peakWorkload - baseline.metrics.peakWorkload,
   400→        percentChange: (simulated.metrics.peakWorkload - baseline.metrics.peakWorkload)
   401→          / baseline.metrics.peakWorkload
   402→      },
   403→      averageWorkload: {
   404→        baseline: baseline.metrics.averageWorkload,
   405→        simulated: simulated.metrics.averageWorkload,
   406→        difference: simulated.metrics.averageWorkload - baseline.metrics.averageWorkload
   407→      },
   408→      workloadVariance: {
   409→        baseline: baseline.metrics.workloadVariance,
   410→        simulated: simulated.metrics.workloadVariance,
   411→        improvement: baseline.metrics.workloadVariance > simulated.metrics.workloadVariance
   412→      }
   413→    };
   414→  }
   415→
   416→  private calculateImpacts(
   417→    baseline: Schedule,
   418→    simulated: Schedule,
   419→    scenario: SimulationScenario
   420→  ): SimulationImpacts {
   421→    return {
   422→      resourceImpact: this.calculateResourceImpact(baseline, simulated),
   423→      costImpact: this.calculateCostImpact(baseline, simulated),
   424→      complianceImpact: this.calculateComplianceImpact(baseline, simulated),
   425→      feasibilityRisk: this.assessFeasibilityRisk(simulated)
   426→    };
   427→  }
   428→}
   429→```
   430→
   431→### Impact Analysis
   432→
   433→```typescript
   434→interface SimulationImpacts {
   435→  resourceImpact: ResourceImpact;
   436→  costImpact: CostImpact;
   437→  complianceImpact: ComplianceImpact;
   438→  feasibilityRisk: FeasibilityRisk;
   439→}
   440→
   441→interface ResourceImpact {
   442→  peakDemandChange: number;        // Percentage
   443→  averageDemandChange: number;     // Percentage
   444→  overCapacityPeriods: number;
   445→  additionalResourcesNeeded: ResourceRequirement[];
   446→}
   447→
   448→interface CostImpact {
   449→  laborCostChange: number;
   450→  partsCostChange: number;
   451→  overheadCostChange: number;
   452→  totalCostChange: number;
   453→  percentageChange: number;
   454→}
   455→
   456→interface ComplianceImpact {
   457→  eventsOnTime: number;
   458→  eventsEarly: number;
   459→  eventsLate: number;
   460→  complianceRate: number;
   461→  riskScore: number;  // 0-100
   462→}
   463→
   464→interface FeasibilityRisk {
   465→  level: 'low' | 'medium' | 'high';
   466→  factors: RiskFactor[];
   467→  mitigations: string[];
   468→}
   469→
   470→function calculateResourceImpact(
   471→  baseline: Schedule,
   472→  simulated: Schedule
   473→): ResourceImpact {
   474→  const baselinePeak = baseline.metrics.peakWorkload;
   475→  const simulatedPeak = simulated.metrics.peakWorkload;
   476→
   477→  const peakDemandChange = (simulatedPeak - baselinePeak) / baselinePeak;
   478→
   479→  const baselineAvg = baseline.metrics.averageWorkload;
   480→  const simulatedAvg = simulated.metrics.averageWorkload;
   481→
   482→  const averageDemandChange = (simulatedAvg - baselineAvg) / baselineAvg;
   483→
   484→  // Count over-capacity periods
   485→  const capacity = baseline.capacity.perPeriod;
   486→  const overCapacityPeriods = simulated.workloadByPeriod
   487→    .filter(w => w > capacity).length;
   488→
   489→  // Calculate additional resources needed
   490→  const additionalResourcesNeeded: ResourceRequirement[] = [];
   491→
   492→  if (peakDemandChange > 0.1) {  // More than 10% increase
   493→    additionalResourcesNeeded.push({
   494→      resourceType: 'technician_hours',
   495→      amount: (simulatedPeak - baselinePeak) * 1.1,  // 10% buffer
   496→      timing: 'peak_periods'
   497→    });
   498→  }
   499→
   500→  return {
   501→    peakDemandChange,
   502→    averageDemandChange,
   503→    overCapacityPeriods,
   504→    additionalResourcesNeeded
   505→  };
   506→}
   507→```
   508→
   509→## Scenario Comparison
   510→
   511→### Multi-Scenario Comparison
   512→
   513→```typescript
   514→interface MultiScenarioComparison {
   515→  baseline: ScheduleSummary;
   516→  scenarios: ScenarioSummary[];
   517→  rankings: ScenarioRanking;
   518→  recommendation: string;
   519→}
   520→
   521→interface ScenarioSummary {
   522→  scenarioId: string;
   523→  name: string;
   524→  metrics: {
   525→    peakWorkload: number;
   526→    averageWorkload: number;
   527→    variance: number;
   528→    totalCost: number;
   529→    complianceRate: number;
   530→  };
   531→  feasible: boolean;
   532→}
   533→
   534→interface ScenarioRanking {
   535→  byPeakWorkload: string[];      // Scenario IDs, best first
   536→  byVariance: string[];
   537→  byCost: string[];
   538→  byCompliance: string[];
   539→  overall: string[];              // Weighted ranking
   540→}
   541→
   542→async function compareScenarios(
   543→  scenarioIds: string[],
   544→  weights: RankingWeights
   545→): Promise<MultiScenarioComparison> {
   546→  const engine = new SimulationEngine(/* deps */);
   547→
   548→  const results: SimulationResult[] = [];
   549→
   550→  for (const scenarioId of scenarioIds) {
   551→    const scenario = await scenarioRepo.get(scenarioId);
   552→    const result = await engine.runSimulation(scenario);
   553→    results.push(result);
   554→  }
   555→
   556→  // Extract summaries
   557→  const scenarios = results.map(r => ({
   558→    scenarioId: r.scenarioId,
   559→    name: r.scenario.name,
   560→    metrics: {
   561→      peakWorkload: r.simulatedSchedule.metrics.peakWorkload,
   562→      averageWorkload: r.simulatedSchedule.metrics.averageWorkload,
   563→      variance: r.simulatedSchedule.metrics.workloadVariance,
   564→      totalCost: r.impacts.costImpact.totalCost,
   565→      complianceRate: r.impacts.complianceImpact.complianceRate
   566→    },
   567→    feasible: r.simulatedSchedule.status !== 'infeasible'
   568→  }));
   569→
   570→  // Create rankings
   571→  const rankings = createRankings(scenarios, weights);
   572→
   573→  // Generate recommendation
   574→  const recommendation = generateRecommendation(scenarios, rankings);
   575→
   576→  return {
   577→    baseline: await getBaselineSummary(),
   578→    scenarios,
   579→    rankings,
   580→    recommendation
   581→  };
   582→}
   583→
   584→function createRankings(
   585→  scenarios: ScenarioSummary[],
   586→  weights: RankingWeights
   587→): ScenarioRanking {
   588→  const feasible = scenarios.filter(s => s.feasible);
   589→
   590→  return {
   591→    byPeakWorkload: [...feasible]
   592→      .sort((a, b) => a.metrics.peakWorkload - b.metrics.peakWorkload)
   593→      .map(s => s.scenarioId),
   594→
   595→    byVariance: [...feasible]
   596→      .sort((a, b) => a.metrics.variance - b.metrics.variance)
   597→      .map(s => s.scenarioId),
   598→
   599→    byCost: [...feasible]
   600→      .sort((a, b) => a.metrics.totalCost - b.metrics.totalCost)
   601→      .map(s => s.scenarioId),
   602→
   603→    byCompliance: [...feasible]
   604→      .sort((a, b) => b.metrics.complianceRate - a.metrics.complianceRate)
   605→      .map(s => s.scenarioId),
   606→
   607→    overall: calculateOverallRanking(feasible, weights)
   608→  };
   609→}
   610→
   611→function calculateOverallRanking(
   612→  scenarios: ScenarioSummary[],
   613→  weights: RankingWeights
   614→): string[] {
   615→  // Normalize metrics to 0-1 scale
   616→  const normalized = scenarios.map(s => ({
   617→    scenarioId: s.scenarioId,
   618→    score: 0
   619→  }));
   620→
   621→  const metrics = ['peakWorkload', 'variance', 'totalCost', 'complianceRate'];
   622→
   623→  for (const metric of metrics) {
   624→    const values = scenarios.map(s => s.metrics[metric as keyof typeof s.metrics]);
   625→    const min = Math.min(...values);
   626→    const max = Math.max(...values);
   627→    const range = max - min || 1;
   628→
   629→    for (let i = 0; i < scenarios.length; i++) {
   630→      const value = scenarios[i].metrics[metric as keyof typeof scenarios[0].metrics];
   631→      const normalizedValue = (value - min) / range;
   632→
   633→      // For compliance, higher is better; for others, lower is better
   634→      const score = metric === 'complianceRate'
   635→        ? normalizedValue
   636→        : 1 - normalizedValue;
   637→
   638→      const weight = weights[metric as keyof RankingWeights] ?? 0.25;
   639→      normalized[i].score += score * weight;
   640→    }
   641→  }
   642→
   643→  return normalized
   644→    .sort((a, b) => b.score - a.score)
   645→    .map(n => n.scenarioId);
   646→}
   647→```
