# What-If Simulations

This document covers what-if simulation features for fleet maintenance scheduling, enabling planners to explore alternative scenarios and their impacts.

## What-If Simulation Overview

### Purpose

```typescript
interface WhatIfSimulation {
  definition: 'Tool for exploring hypothetical scheduling scenarios';

  useCases: [
    'Impact of adding/removing assets from fleet',
    'Effect of changing maintenance intervals',
    'Resource capacity adjustments',
    'Seasonal demand variations',
    'Budget constraint analysis',
    'Risk assessment'
  ];

  benefits: [
    'Better decision making',
    'Risk identification',
    'Resource optimization',
    'Stakeholder communication',
    'Contingency planning'
  ];
}
```

### Simulation Types

```typescript
type SimulationType =
  | 'fleet_change'           // Add/remove assets
  | 'interval_change'        // Modify maintenance intervals
  | 'capacity_change'        // Adjust resource capacity
  | 'demand_change'          // Change usage patterns
  | 'constraint_change'      // Modify constraints
  | 'multi_scenario';        // Combine multiple changes

interface SimulationScenario {
  id: string;
  name: string;
  description: string;
  type: SimulationType;
  baselineScheduleId: string;
  changes: ScenarioChange[];
  createdAt: Date;
  createdBy: string;
}
```

## Scenario Definition

### Change Types

```typescript
interface ScenarioChange {
  type: ChangeType;
  target: ChangeTarget;
  parameters: ChangeParameters;
}

type ChangeType =
  | 'add'
  | 'remove'
  | 'modify'
  | 'replace';

interface ChangeTarget {
  entityType: 'asset' | 'maintenance_type' | 'resource' | 'constraint';
  entityId?: string;
  filter?: TargetFilter;  // Apply to multiple entities
}

interface TargetFilter {
  assetType?: string;
  maintenanceCode?: string;
  fleetId?: string;
}

// Example change parameters by type
interface FleetChangeParams {
  assets: AssetDefinition[];
  effectiveDate: Date;
}

interface IntervalChangeParams {
  maintenanceTypeId: string;
  newIntervalMileage?: number;
  newIntervalDays?: number;
  changePercentage?: number;  // Alternative: change by percentage
}

interface CapacityChangeParams {
  resourceId: string;
  newCapacity?: number;
  capacityMultiplier?: number;
  periodRange?: { start: number; end: number };
}

interface DemandChangeParams {
  assetIds?: string[];
  usageMultiplier: number;
  seasonalPattern?: SeasonalPattern;
}
```

### Scenario Builder

```typescript
class ScenarioBuilder {
  private changes: ScenarioChange[] = [];
  private name: string = '';
  private description: string = '';

  constructor(
    private baselineScheduleId: string
  ) {}

  withName(name: string): this {
    this.name = name;
    return this;
  }

  withDescription(description: string): this {
    this.description = description;
    return this;
  }

  addAssets(assets: AssetDefinition[]): this {
    this.changes.push({
      type: 'add',
      target: { entityType: 'asset' },
      parameters: { assets, effectiveDate: new Date() }
    });
    return this;
  }

  removeAssets(assetIds: string[]): this {
    for (const assetId of assetIds) {
      this.changes.push({
        type: 'remove',
        target: { entityType: 'asset', entityId: assetId },
        parameters: {}
      });
    }
    return this;
  }

  modifyInterval(
    maintenanceTypeId: string,
    changePercentage: number
  ): this {
    this.changes.push({
      type: 'modify',
      target: { entityType: 'maintenance_type', entityId: maintenanceTypeId },
      parameters: { changePercentage }
    });
    return this;
  }

  adjustCapacity(
    resourceId: string,
    multiplier: number,
    periods?: { start: number; end: number }
  ): this {
    this.changes.push({
      type: 'modify',
      target: { entityType: 'resource', entityId: resourceId },
      parameters: {
        capacityMultiplier: multiplier,
        periodRange: periods
      }
    });
    return this;
  }

  changeUsagePattern(
    multiplier: number,
    assetFilter?: TargetFilter
  ): this {
    this.changes.push({
      type: 'modify',
      target: {
        entityType: 'asset',
        filter: assetFilter
      },
      parameters: { usageMultiplier: multiplier }
    });
    return this;
  }

  build(): SimulationScenario {
    return {
      id: crypto.randomUUID(),
      name: this.name,
      description: this.description,
      type: this.determineType(),
      baselineScheduleId: this.baselineScheduleId,
      changes: this.changes,
      createdAt: new Date(),
      createdBy: ''  // Set by service
    };
  }

  private determineType(): SimulationType {
    if (this.changes.length > 1) {
      const types = new Set(this.changes.map(c => c.target.entityType));
      if (types.size > 1) return 'multi_scenario';
    }

    const firstChange = this.changes[0];
    switch (firstChange?.target.entityType) {
      case 'asset': return 'fleet_change';
      case 'maintenance_type': return 'interval_change';
      case 'resource': return 'capacity_change';
      default: return 'constraint_change';
    }
  }
}

// Usage example
const scenario = new ScenarioBuilder('schedule-123')
  .withName('Fleet Expansion 2025')
  .withDescription('Adding 10 new vehicles in Q1 2025')
  .addAssets(newVehicles)
  .adjustCapacity('technician-hours', 1.2)
  .build();
```

## Simulation Engine

### Core Engine

```typescript
// services/simulation-engine.service.ts
export class SimulationEngine {
  constructor(
    private readonly scheduleRepo: ScheduleRepository,
    private readonly solverService: SolverService,
    private readonly forecastService: ForecastService
  ) {}

  async runSimulation(
    scenario: SimulationScenario
  ): Promise<SimulationResult> {
    // 1. Load baseline
    const baseline = await this.scheduleRepo.getWithEvents(
      scenario.baselineScheduleId
    );

    // 2. Create modified input data
    const modifiedInput = await this.applyChanges(baseline, scenario.changes);

    // 3. Run optimization with modified data
    const simulatedSchedule = await this.solverService.solve(modifiedInput);

    // 4. Compare results
    const comparison = this.compareSchedules(baseline, simulatedSchedule);

    // 5. Calculate impacts
    const impacts = this.calculateImpacts(baseline, simulatedSchedule, scenario);

    return {
      scenarioId: scenario.id,
      baselineScheduleId: baseline.id,
      simulatedSchedule,
      comparison,
      impacts,
      executedAt: new Date()
    };
  }

  private async applyChanges(
    baseline: Schedule,
    changes: ScenarioChange[]
  ): Promise<SolverInput> {
    let assets = [...baseline.assets];
    let maintenanceTypes = [...baseline.maintenanceTypes];
    let capacity = { ...baseline.capacity };
    let forecasts = [...baseline.forecasts];

    for (const change of changes) {
      switch (change.target.entityType) {
        case 'asset':
          ({ assets, forecasts } = this.applyAssetChange(
            assets, forecasts, change
          ));
          break;

        case 'maintenance_type':
          maintenanceTypes = this.applyMaintenanceChange(
            maintenanceTypes, change
          );
          break;

        case 'resource':
          capacity = this.applyCapacityChange(capacity, change);
          break;
      }
    }

    // Regenerate events based on modified data
    const events = await this.generateEvents(
      assets,
      maintenanceTypes,
      forecasts,
      baseline.periods.length
    );

    return {
      events,
      num_periods: baseline.periods.length,
      capacity,
      config: baseline.solverConfig
    };
  }

  private applyAssetChange(
    assets: Asset[],
    forecasts: MileageForecast[],
    change: ScenarioChange
  ): { assets: Asset[]; forecasts: MileageForecast[] } {
    if (change.type === 'add') {
      const params = change.parameters as FleetChangeParams;
      const newAssets = params.assets;

      // Generate forecasts for new assets
      const newForecasts = newAssets.flatMap(asset =>
        this.forecastService.generateLinearForecast(asset, params.effectiveDate)
      );

      return {
        assets: [...assets, ...newAssets],
        forecasts: [...forecasts, ...newForecasts]
      };
    }

    if (change.type === 'remove') {
      const assetId = change.target.entityId!;
      return {
        assets: assets.filter(a => a.id !== assetId),
        forecasts: forecasts.filter(f => f.assetId !== assetId)
      };
    }

    if (change.type === 'modify' && change.parameters.usageMultiplier) {
      const multiplier = change.parameters.usageMultiplier;
      const filter = change.target.filter;

      const affectedIds = assets
        .filter(a => !filter || this.matchesFilter(a, filter))
        .map(a => a.id);

      return {
        assets,
        forecasts: forecasts.map(f => {
          if (affectedIds.includes(f.assetId)) {
            return {
              ...f,
              projectedMileage: Math.round(f.projectedMileage * multiplier)
            };
          }
          return f;
        })
      };
    }

    return { assets, forecasts };
  }

  private compareSchedules(
    baseline: Schedule,
    simulated: Schedule
  ): ScheduleComparison {
    return {
      totalEvents: {
        baseline: baseline.events.length,
        simulated: simulated.events.length,
        difference: simulated.events.length - baseline.events.length
      },
      peakWorkload: {
        baseline: baseline.metrics.peakWorkload,
        simulated: simulated.metrics.peakWorkload,
        difference: simulated.metrics.peakWorkload - baseline.metrics.peakWorkload,
        percentChange: (simulated.metrics.peakWorkload - baseline.metrics.peakWorkload)
          / baseline.metrics.peakWorkload
      },
      averageWorkload: {
        baseline: baseline.metrics.averageWorkload,
        simulated: simulated.metrics.averageWorkload,
        difference: simulated.metrics.averageWorkload - baseline.metrics.averageWorkload
      },
      workloadVariance: {
        baseline: baseline.metrics.workloadVariance,
        simulated: simulated.metrics.workloadVariance,
        improvement: baseline.metrics.workloadVariance > simulated.metrics.workloadVariance
      }
    };
  }

  private calculateImpacts(
    baseline: Schedule,
    simulated: Schedule,
    scenario: SimulationScenario
  ): SimulationImpacts {
    return {
      resourceImpact: this.calculateResourceImpact(baseline, simulated),
      costImpact: this.calculateCostImpact(baseline, simulated),
      complianceImpact: this.calculateComplianceImpact(baseline, simulated),
      feasibilityRisk: this.assessFeasibilityRisk(simulated)
    };
  }
}
```

### Impact Analysis

```typescript
interface SimulationImpacts {
  resourceImpact: ResourceImpact;
  costImpact: CostImpact;
  complianceImpact: ComplianceImpact;
  feasibilityRisk: FeasibilityRisk;
}

interface ResourceImpact {
  peakDemandChange: number;        // Percentage
  averageDemandChange: number;     // Percentage
  overCapacityPeriods: number;
  additionalResourcesNeeded: ResourceRequirement[];
}

interface CostImpact {
  laborCostChange: number;
  partsCostChange: number;
  overheadCostChange: number;
  totalCostChange: number;
  percentageChange: number;
}

interface ComplianceImpact {
  eventsOnTime: number;
  eventsEarly: number;
  eventsLate: number;
  complianceRate: number;
  riskScore: number;  // 0-100
}

interface FeasibilityRisk {
  level: 'low' | 'medium' | 'high';
  factors: RiskFactor[];
  mitigations: string[];
}

function calculateResourceImpact(
  baseline: Schedule,
  simulated: Schedule
): ResourceImpact {
  const baselinePeak = baseline.metrics.peakWorkload;
  const simulatedPeak = simulated.metrics.peakWorkload;

  const peakDemandChange = (simulatedPeak - baselinePeak) / baselinePeak;

  const baselineAvg = baseline.metrics.averageWorkload;
  const simulatedAvg = simulated.metrics.averageWorkload;

  const averageDemandChange = (simulatedAvg - baselineAvg) / baselineAvg;

  // Count over-capacity periods
  const capacity = baseline.capacity.perPeriod;
  const overCapacityPeriods = simulated.workloadByPeriod
    .filter(w => w > capacity).length;

  // Calculate additional resources needed
  const additionalResourcesNeeded: ResourceRequirement[] = [];

  if (peakDemandChange > 0.1) {  // More than 10% increase
    additionalResourcesNeeded.push({
      resourceType: 'technician_hours',
      amount: (simulatedPeak - baselinePeak) * 1.1,  // 10% buffer
      timing: 'peak_periods'
    });
  }

  return {
    peakDemandChange,
    averageDemandChange,
    overCapacityPeriods,
    additionalResourcesNeeded
  };
}
```

## Scenario Comparison

### Multi-Scenario Comparison

```typescript
interface MultiScenarioComparison {
  baseline: ScheduleSummary;
  scenarios: ScenarioSummary[];
  rankings: ScenarioRanking;
  recommendation: string;
}

interface ScenarioSummary {
  scenarioId: string;
  name: string;
  metrics: {
    peakWorkload: number;
    averageWorkload: number;
    variance: number;
    totalCost: number;
    complianceRate: number;
  };
  feasible: boolean;
}

interface ScenarioRanking {
  byPeakWorkload: string[];      // Scenario IDs, best first
  byVariance: string[];
  byCost: string[];
  byCompliance: string[];
  overall: string[];              // Weighted ranking
}

async function compareScenarios(
  scenarioIds: string[],
  weights: RankingWeights
): Promise<MultiScenarioComparison> {
  const engine = new SimulationEngine(/* deps */);

  const results: SimulationResult[] = [];

  for (const scenarioId of scenarioIds) {
    const scenario = await scenarioRepo.get(scenarioId);
    const result = await engine.runSimulation(scenario);
    results.push(result);
  }

  // Extract summaries
  const scenarios = results.map(r => ({
    scenarioId: r.scenarioId,
    name: r.scenario.name,
    metrics: {
      peakWorkload: r.simulatedSchedule.metrics.peakWorkload,
      averageWorkload: r.simulatedSchedule.metrics.averageWorkload,
      variance: r.simulatedSchedule.metrics.workloadVariance,
      totalCost: r.impacts.costImpact.totalCost,
      complianceRate: r.impacts.complianceImpact.complianceRate
    },
    feasible: r.simulatedSchedule.status !== 'infeasible'
  }));

  // Create rankings
  const rankings = createRankings(scenarios, weights);

  // Generate recommendation
  const recommendation = generateRecommendation(scenarios, rankings);

  return {
    baseline: await getBaselineSummary(),
    scenarios,
    rankings,
    recommendation
  };
}

function createRankings(
  scenarios: ScenarioSummary[],
  weights: RankingWeights
): ScenarioRanking {
  const feasible = scenarios.filter(s => s.feasible);

  return {
    byPeakWorkload: [...feasible]
      .sort((a, b) => a.metrics.peakWorkload - b.metrics.peakWorkload)
      .map(s => s.scenarioId),

    byVariance: [...feasible]
      .sort((a, b) => a.metrics.variance - b.metrics.variance)
      .map(s => s.scenarioId),

    byCost: [...feasible]
      .sort((a, b) => a.metrics.totalCost - b.metrics.totalCost)
      .map(s => s.scenarioId),

    byCompliance: [...feasible]
      .sort((a, b) => b.metrics.complianceRate - a.metrics.complianceRate)
      .map(s => s.scenarioId),

    overall: calculateOverallRanking(feasible, weights)
  };
}

function calculateOverallRanking(
  scenarios: ScenarioSummary[],
  weights: RankingWeights
): string[] {
  // Normalize metrics to 0-1 scale
  const normalized = scenarios.map(s => ({
    scenarioId: s.scenarioId,
    score: 0
  }));

  const metrics = ['peakWorkload', 'variance', 'totalCost', 'complianceRate'];

  for (const metric of metrics) {
    const values = scenarios.map(s => s.metrics[metric as keyof typeof s.metrics]);
    const min = Math.min(...values);
    const max = Math.max(...values);
    const range = max - min || 1;

    for (let i = 0; i < scenarios.length; i++) {
      const value = scenarios[i].metrics[metric as keyof typeof scenarios[0].metrics];
      const normalizedValue = (value - min) / range;

      // For compliance, higher is better; for others, lower is better
      const score = metric === 'complianceRate'
        ? normalizedValue
        : 1 - normalizedValue;

      const weight = weights[metric as keyof RankingWeights] ?? 0.25;
      normalized[i].score += score * weight;
    }
  }

  return normalized
    .sort((a, b) => b.score - a.score)
    .map(n => n.scenarioId);
}
