```typescript
// services/what-if.service.ts
export class WhatIfService {
  constructor(
    private readonly engine: SimulationEngine,
    private readonly scenarioRepo: ScenarioRepository,
    private readonly resultRepo: SimulationResultRepository
  ) {}

  async createScenario(
    baselineScheduleId: string,
    builder: (b: ScenarioBuilder) => ScenarioBuilder
  ): Promise<SimulationScenario> {
    const scenario = builder(new ScenarioBuilder(baselineScheduleId)).build();
    await this.scenarioRepo.create(scenario);
    return scenario;
  }

  async runScenario(scenarioId: string): Promise<SimulationResult> {
    const scenario = await this.scenarioRepo.get(scenarioId);
    const result = await this.engine.runSimulation(scenario);
    await this.resultRepo.create(result);
    return result;
  }

  async compareMultipleScenarios(
    scenarioIds: string[],
    weights?: RankingWeights
  ): Promise<MultiScenarioComparison> {
    return compareScenarios(scenarioIds, weights ?? defaultWeights);
  }

  async getScenarioTemplates(): Promise<ScenarioTemplate[]> {
    return [
      {
        id: 'fleet-expansion-10',
        name: '10% Fleet Expansion',
        description: 'Simulate adding 10% more assets to the fleet',
        builder: (b, baseAssets) => b
          .withName('Fleet Expansion +10%')
          .addAssets(generateNewAssets(baseAssets, 0.1))
      },
      {
        id: 'capacity-reduction-20',
        name: '20% Capacity Reduction',
        description: 'Simulate reducing workshop capacity by 20%',
        builder: (b) => b
          .withName('Capacity Reduction -20%')
          .adjustCapacity('technician-hours', 0.8)
      },
      {
        id: 'interval-extension-15',
