    10→---
    11→
    12→# Rolling Horizon Planning
    13→
    14→Long-term maintenance scheduling (5-15 years) cannot be solved as a single optimization problem. Rolling horizon decomposition breaks the problem into manageable windows while maintaining plan coherence.
    15→
    16→## Why Rolling Horizon
    17→
    18→### The Scalability Problem
    19→
    20→Direct optimization of long horizons faces challenges:
    21→
    22→```typescript
    23→interface ScalabilityChallenge {
    24→  scenario: {
    25→    assets: 100;
    26→    maintenanceTypes: 5;
    27→    horizonYears: 10;
    28→    periodsPerYear: 52;  // Weekly
    29→  };
    30→
    31→  problemSize: {
    32→    totalPeriods: 520;
    33→    eventsPerAsset: 50;  // Average over 10 years
    34→    totalEvents: 5000;
    35→    binaryVariables: 2_600_000;  // events × periods
    36→  };
    37→
    38→  solverBehavior: {
    39→    memory: '8+ GB';
    40→    solveTime: 'Hours to days';
    41→    solutionQuality: 'Poor due to timeout';
    42→  };
    43→}
    44→```
    45→
    46→### Rolling Horizon Solution
    47→
    48→Break the problem into overlapping windows:
    49→
    50→```typescript
    51→interface RollingHorizonConcept {
    52→  principle: 'Solve in windows, fix decisions, roll forward';
    53→
    54→  benefits: [
    55→    'Manageable problem size',
    56→    'Quick re-planning',
    57→    'Adapts to changes',
    58→    'Bounded memory usage'
    59→  ];
    60→
    61→  tradeoff: 'May miss global optimizations across windows';
    62→}
    63→```
    64→
    65→## Rolling Horizon Architecture
    66→
    67→### Window Structure
    68→
    69→```
    70→Time ────────────────────────────────────────────────────────────────────►
    71→
    72→Solve 1:  ├──── Frozen ────┼──── Flexible ────┼──── Aggregate ────┤
    73→                           │                   │
    74→Solve 2:                   ├──── Frozen ────┼──── Flexible ────┼──── Aggregate ────┤
    75→                                              │                   │
    76→Solve 3:                                      ├──── Frozen ────┼──── Flexible ────┼────►
    77→
    78→```
    79→
    80→### Configuration Parameters
    81→
    82→```typescript
    83→interface RollingHorizonConfig {
    84→  // Window sizes (in periods, e.g., weeks)
    85→  windowSize: number;       // Total window length
    86→  frozenHorizon: number;    // Periods locked after solve
    87→  flexibleHorizon: number;  // Full detail optimization
    88→  aggregateHorizon: number; // Reduced detail for stability
    89→
    90→  // Overlap and continuity
    91→  overlapPeriods: number;   // Shared between windows for stability
    92→  stabilityWeight: number;  // Penalty for changing previous decisions
    93→
    94→  // Triggering
    95→  rollFrequency: number;    // How often to roll (periods)
    96→  triggerOnChange: boolean; // Re-solve on significant changes
    97→}
    98→
    99→const defaultConfig: RollingHorizonConfig = {
   100→  windowSize: 52,        // 1 year total window
   101→  frozenHorizon: 4,      // Lock 1 month
   102→  flexibleHorizon: 13,   // Optimize 3 months in detail
   103→  aggregateHorizon: 35,  // 9 months aggregate
   104→  overlapPeriods: 4,     // 1 month overlap
   105→  stabilityWeight: 0.1,  // Light penalty for changes
   106→  rollFrequency: 4,      // Roll monthly
   107→  triggerOnChange: true
   108→};
   109→```
   110→
   111→## Implementation
   112→
   113→### Rolling Horizon Solver
   114→
   115→```typescript
   116→interface RollingHorizonSolver {
   117→  config: RollingHorizonConfig;
   118→  currentSchedule: Schedule | null;
   119→  currentPeriod: number;
   120→
   121→  solve(): Promise<Schedule>;
   122→  roll(): void;
   123→  handleChange(change: ScheduleChange): Promise<void>;
   124→}
   125→
   126→class RollingHorizonScheduler implements RollingHorizonSolver {
   127→  constructor(
   128→    private config: RollingHorizonConfig,
   129→    private solver: SolverAdapter,
   130→    private problemBuilder: ProblemBuilder
   131→  ) {}
   132→
   133→  async solve(): Promise<Schedule> {
   134→    // Extract current window
   135→    const windowStart = this.currentPeriod;
   136→    const windowEnd = windowStart + this.config.windowSize;
   137→
   138→    // Build problem for window
   139→    const problem = await this.problemBuilder.buildWindowProblem({
   140→      start: windowStart,
   141→      end: windowEnd,
   142→      frozenDecisions: this.getFrozenDecisions(),
   143→      aggregationLevel: this.getAggregationLevels()
   144→    });
   145→
   146→    // Add stability constraints if previous schedule exists
   147→    if (this.currentSchedule) {
   148→      this.addStabilityConstraints(problem, this.currentSchedule);
   149→    }
   150→
   151→    // Solve
   152→    const solution = await this.solver.solve(problem);
   153→
   154→    // Merge with existing schedule
   155→    this.currentSchedule = this.mergeSchedule(solution);
   156→
   157→    return this.currentSchedule;
   158→  }
   159→
   160→  private getAggregationLevels(): AggregationLevel[] {
   161→    const flexEnd = this.currentPeriod + this.config.flexibleHorizon;
   162→    const aggEnd = this.currentPeriod + this.config.windowSize;
   163→
   164→    return [
   165→      {
   166→        start: this.currentPeriod,
   167→        end: flexEnd,
   168→        level: 'detailed',
   169→        periodGrouping: 1  // Weekly
   170→      },
   171→      {
   172→        start: flexEnd,
   173→        end: aggEnd,
   174→        level: 'aggregate',
   175→        periodGrouping: 4  // Monthly
   176→      }
   177→    ];
   178→  }
   179→
   180→  private addStabilityConstraints(
   181→    problem: SchedulingProblem,
   182→    previousSchedule: Schedule
   183→  ): void {
   184→    // For events in overlap period, penalize changes
   185→    const overlapStart = this.currentPeriod;
   186→    const overlapEnd = overlapStart + this.config.overlapPeriods;
   187→
   188→    for (const event of previousSchedule.events) {
   189→      if (event.scheduledPeriod >= overlapStart &&
   190→          event.scheduledPeriod < overlapEnd) {
   191→        // Add soft constraint preferring same period
   192→        problem.addSoftConstraint({
   193→          type: 'prefer_period',
   194→          eventId: event.id,
   195→          preferredPeriod: event.scheduledPeriod,
   196→          violationPenalty: this.config.stabilityWeight
   197→        });
   198→      }
   199→    }
   200→  }
   201→
   202→  roll(): void {
   203→    this.currentPeriod += this.config.rollFrequency;
   204→    // Frozen decisions are now in the past
   205→  }
   206→}
   207→```
   208→
   209→### Window Problem Builder
   210→
   211→```typescript
   212→interface WindowProblem {
   213→  events: WindowEvent[];
   214→  periods: WindowPeriod[];
   215→  constraints: Constraint[];
   216→  objective: Objective;
   217→}
   218→
   219→interface WindowEvent {
   220→  id: string;
   221→  assetId: string;
   222→  originalEvent: MaintenanceEvent;
   223→  windowEarliest: number;  // Relative to window start
   224→  windowLatest: number;
   225→  aggregated: boolean;     // Part of aggregate group
   226→  groupId?: string;        // If aggregated
   227→}
   228→
   229→interface WindowPeriod {
   230→  index: number;
   231→  absolutePeriod: number;
   232→  aggregationLevel: 'detailed' | 'aggregate';
   233→  capacity: number;
   234→}
   235→
   236→class ProblemBuilder {
   237→  async buildWindowProblem(params: {
   238→    start: number;
   239→    end: number;
   240→    frozenDecisions: FrozenDecision[];
   241→    aggregationLevel: AggregationLevel[];
   242→  }): Promise<WindowProblem> {
   243→    // Load events that could occur in window
   244→    const candidateEvents = await this.loadCandidateEvents(
   245→      params.start,
   246→      params.end
   247→    );
   248→
   249→    // Apply frozen decisions
   250→    const activeEvents = this.applyFrozenDecisions(
   251→      candidateEvents,
   252→      params.frozenDecisions
   253→    );
   254→
   255→    // Apply aggregation
   256→    const windowEvents = this.applyAggregation(
   257→      activeEvents,
   258→      params.aggregationLevel
   259→    );
   260→
   261→    // Build periods with appropriate capacity
   262→    const periods = this.buildPeriods(
   263→      params.start,
   264→      params.end,
   265→      params.aggregationLevel
   266→    );
   267→
   268→    // Standard constraints
   269→    const constraints = this.buildConstraints(windowEvents, periods);
   270→
   271→    // Objective
   272→    const objective = this.buildObjective(windowEvents, periods);
   273→
   274→    return { events: windowEvents, periods, constraints, objective };
   275→  }
   276→
   277→  private applyAggregation(
   278→    events: WindowEvent[],
   279→    levels: AggregationLevel[]
   280→  ): WindowEvent[] {
   281→    const result: WindowEvent[] = [];
   282→
   283→    for (const event of events) {
   284→      const level = this.findAggregationLevel(event.windowEarliest, levels);
   285→
   286→      if (level.level === 'detailed') {
   287→        result.push(event);
   288→      } else {
   289→        // Aggregate: group events by asset and time block
   290→        const groupId = this.getAggregateGroup(
   291→          event,
   292→          level.periodGrouping
   293→        );
   294→        result.push({
   295→          ...event,
   296→          aggregated: true,
   297→          groupId
   298→        });
   299→      }
   300→    }
   301→
   302→    return result;
   303→  }
   304→}
   305→```
   306→
   307→### Schedule Merging
   308→
   309→```typescript
   310→interface ScheduleMerger {
   311→  merge(
   312→    existingSchedule: Schedule,
   313→    windowSolution: WindowSolution,
   314→    windowStart: number,
   315→    frozenHorizon: number
   316→  ): Schedule;
   317→}
   318→
   319→class ScheduleMergerImpl implements ScheduleMerger {
   320→  merge(
   321→    existing: Schedule,
   322→    window: WindowSolution,
   323→    windowStart: number,
   324→    frozenHorizon: number
   325→  ): Schedule {
   326→    const merged: ScheduledEvent[] = [];
   327→
   328→    // Keep frozen events from existing schedule
   329→    const frozenEnd = windowStart + frozenHorizon;
   330→    for (const event of existing.events) {
   331→      if (event.scheduledPeriod < windowStart) {
   332→        // Past events: keep as-is
   333→        merged.push(event);
   334→      } else if (event.scheduledPeriod < frozenEnd) {
   335→        // Frozen but in window: keep existing decision
   336→        merged.push(event);
   337→      }
   338→      // Events after frozen period: will be replaced
   339→    }
   340→
   341→    // Add new decisions from window solution
   342→    for (const event of window.events) {
   343→      if (event.scheduledPeriod >= frozenEnd) {
   344→        merged.push({
   345→          id: event.id,
   346→          assetId: event.assetId,
   347→          maintenanceTypeId: event.maintenanceTypeId,
   348→          scheduledPeriod: event.scheduledPeriod,
   349→          source: 'optimization',
   350→          confidence: event.aggregated ? 'low' : 'high'
   351→        });
   352→      }
   353→    }
   354→
   355→    return {
   356→      events: merged,
   357→      metadata: {
   358→        generatedAt: new Date(),
   359→        windowStart,
   360→        windowEnd: windowStart + window.windowSize,
   361→        solverUsed: window.solverUsed
   362→      }
   363→    };
   364→  }
   365→}
   366→```
   367→
   368→## Aggregation Strategies
   369→
   370→### Temporal Aggregation
   371→
   372→Reduce time granularity for distant periods:
   373→
   374→```typescript
   375→interface TemporalAggregation {
   376→  strategy: 'Group weeks into months or quarters';
   377→
   378→  implementation: {
   379→    detailed: 'Weekly periods (0-13 weeks)';
   380→    monthly: 'Monthly buckets (14-52 weeks)';
   381→    quarterly: 'Quarterly buckets (53+ weeks)';
   382→  };
   383→
   384→  effect: {
   385→    variableReduction: '4x for monthly, 13x for quarterly';
   386→    constraintReduction: 'Proportional';
   387→    solutionQuality: 'Slightly reduced in aggregate periods';
   388→  };
   389→}
   390→
   391→function aggregatePeriods(
   392→  periods: number[],
   393→  strategy: AggregationStrategy
   394→): AggregatedPeriod[] {
   395→  const result: AggregatedPeriod[] = [];
   396→
   397→  let currentGroup: number[] = [];
   398→  let currentLevel = 'detailed';
   399→
   400→  for (const period of periods) {
   401→    const level = strategy.getLevelForPeriod(period);
   402→
   403→    if (level !== currentLevel && currentGroup.length > 0) {
   404→      result.push({
   405→        periods: [...currentGroup],
   406→        level: currentLevel,
   407→        capacity: sumCapacity(currentGroup)
   408→      });
   409→      currentGroup = [];
   410→    }
   411→
   412→    currentGroup.push(period);
   413→    currentLevel = level;
   414→  }
   415→
   416→  if (currentGroup.length > 0) {
   417→    result.push({
   418→      periods: currentGroup,
   419→      level: currentLevel,
   420→      capacity: sumCapacity(currentGroup)
   421→    });
   422→  }
   423→
   424→  return result;
   425→}
   426→```
   427→
   428→### Event Aggregation
   429→
   430→Group similar events:
   431→
   432→```typescript
   433→interface EventAggregation {
   434→  strategy: 'Group maintenance events by type and time block';
   435→
   436→  grouping: {
   437→    byAsset: false;  // Keep asset-specific in detailed
   438→    byType: true;    // Group same maintenance types
   439→    byTimeBlock: true;  // Within aggregate period
   440→  };
   441→
   442→  example: {
   443→    detailed: '10 individual PM-A events';
   444→    aggregated: '1 "10x PM-A" event with 10x resources';
   445→  };
   446→}
   447→
   448→function aggregateEvents(
   449→  events: MaintenanceEvent[],
   450→  aggregatePeriods: AggregatedPeriod[]
   451→): AggregatedEvent[] {
   452→  const result: AggregatedEvent[] = [];
   453→
   454→  // Group events by type and aggregate period
   455→  const groups = new Map<string, MaintenanceEvent[]>();
   456→
   457→  for (const event of events) {
   458→    const aggPeriod = findAggregatePeriod(event.targetPeriod, aggregatePeriods);
   459→    if (!aggPeriod) continue;
   460→
   461→    const key = `${event.maintenanceTypeId}_${aggPeriod.id}`;
   462→    if (!groups.has(key)) {
   463→      groups.set(key, []);
   464→    }
   465→    groups.get(key)!.push(event);
   466→  }
   467→
   468→  // Create aggregated events
   469→  for (const [key, groupEvents] of groups) {
   470→    result.push({
   471→      id: `agg_${key}`,
   472→      originalEvents: groupEvents.map(e => e.id),
   473→      count: groupEvents.length,
   474→      totalManHours: sum(groupEvents.map(e => e.manHours)),
