# Rolling Horizon Planning

Long-term maintenance scheduling (5-15 years) cannot be solved as a single optimization problem. Rolling horizon decomposition breaks the problem into manageable windows while maintaining plan coherence.

## Why Rolling Horizon

### The Scalability Problem

Direct optimization of long horizons faces challenges:

```typescript
interface ScalabilityChallenge {
  scenario: {
    assets: 100;
    maintenanceTypes: 5;
    horizonYears: 10;
    periodsPerYear: 52;  // Weekly
  };

  problemSize: {
    totalPeriods: 520;
    eventsPerAsset: 50;  // Average over 10 years
    totalEvents: 5000;
    binaryVariables: 2_600_000;  // events × periods
  };

  solverBehavior: {
    memory: '8+ GB';
    solveTime: 'Hours to days';
    solutionQuality: 'Poor due to timeout';
  };
}
```

### Rolling Horizon Solution

Break the problem into overlapping windows:

```typescript
interface RollingHorizonConcept {
  principle: 'Solve in windows, fix decisions, roll forward';

  benefits: [
    'Manageable problem size',
    'Quick re-planning',
    'Adapts to changes',
    'Bounded memory usage'
  ];

  tradeoff: 'May miss global optimizations across windows';
}
```

## Rolling Horizon Architecture

### Window Structure

```
Time ────────────────────────────────────────────────────────────────────►

Solve 1:  ├──── Frozen ────┼──── Flexible ────┼──── Aggregate ────┤
                           │                   │
Solve 2:                   ├──── Frozen ────┼──── Flexible ────┼──── Aggregate ────┤
                                              │                   │
Solve 3:                                      ├──── Frozen ────┼──── Flexible ────┼────►

```

### Configuration Parameters

```typescript
interface RollingHorizonConfig {
  // Window sizes (in periods, e.g., weeks)
  windowSize: number;       // Total window length
  frozenHorizon: number;    // Periods locked after solve
  flexibleHorizon: number;  // Full detail optimization
  aggregateHorizon: number; // Reduced detail for stability

  // Overlap and continuity
  overlapPeriods: number;   // Shared between windows for stability
  stabilityWeight: number;  // Penalty for changing previous decisions

  // Triggering
  rollFrequency: number;    // How often to roll (periods)
  triggerOnChange: boolean; // Re-solve on significant changes
}

const defaultConfig: RollingHorizonConfig = {
  windowSize: 52,        // 1 year total window
  frozenHorizon: 4,      // Lock 1 month
  flexibleHorizon: 13,   // Optimize 3 months in detail
  aggregateHorizon: 35,  // 9 months aggregate
  overlapPeriods: 4,     // 1 month overlap
  stabilityWeight: 0.1,  // Light penalty for changes
  rollFrequency: 4,      // Roll monthly
  triggerOnChange: true
};
```

## Implementation

### Rolling Horizon Solver

```typescript
interface RollingHorizonSolver {
  config: RollingHorizonConfig;
  currentSchedule: Schedule | null;
  currentPeriod: number;

  solve(): Promise<Schedule>;
  roll(): void;
  handleChange(change: ScheduleChange): Promise<void>;
}

class RollingHorizonScheduler implements RollingHorizonSolver {
  constructor(
    private config: RollingHorizonConfig,
    private solver: SolverAdapter,
    private problemBuilder: ProblemBuilder
  ) {}

  async solve(): Promise<Schedule> {
    // Extract current window
    const windowStart = this.currentPeriod;
    const windowEnd = windowStart + this.config.windowSize;

    // Build problem for window
    const problem = await this.problemBuilder.buildWindowProblem({
      start: windowStart,
      end: windowEnd,
      frozenDecisions: this.getFrozenDecisions(),
      aggregationLevel: this.getAggregationLevels()
    });

    // Add stability constraints if previous schedule exists
    if (this.currentSchedule) {
      this.addStabilityConstraints(problem, this.currentSchedule);
    }

    // Solve
    const solution = await this.solver.solve(problem);

    // Merge with existing schedule
    this.currentSchedule = this.mergeSchedule(solution);

    return this.currentSchedule;
  }

  private getAggregationLevels(): AggregationLevel[] {
    const flexEnd = this.currentPeriod + this.config.flexibleHorizon;
    const aggEnd = this.currentPeriod + this.config.windowSize;

    return [
      {
        start: this.currentPeriod,
        end: flexEnd,
        level: 'detailed',
        periodGrouping: 1  // Weekly
      },
      {
        start: flexEnd,
        end: aggEnd,
        level: 'aggregate',
        periodGrouping: 4  // Monthly
      }
    ];
  }

  private addStabilityConstraints(
    problem: SchedulingProblem,
    previousSchedule: Schedule
  ): void {
    // For events in overlap period, penalize changes
    const overlapStart = this.currentPeriod;
    const overlapEnd = overlapStart + this.config.overlapPeriods;

    for (const event of previousSchedule.events) {
      if (event.scheduledPeriod >= overlapStart &&
          event.scheduledPeriod < overlapEnd) {
        // Add soft constraint preferring same period
        problem.addSoftConstraint({
          type: 'prefer_period',
          eventId: event.id,
          preferredPeriod: event.scheduledPeriod,
          violationPenalty: this.config.stabilityWeight
        });
      }
    }
  }

  roll(): void {
    this.currentPeriod += this.config.rollFrequency;
    // Frozen decisions are now in the past
  }
}
```

### Window Problem Builder

```typescript
interface WindowProblem {
  events: WindowEvent[];
  periods: WindowPeriod[];
  constraints: Constraint[];
  objective: Objective;
}

interface WindowEvent {
  id: string;
  assetId: string;
  originalEvent: MaintenanceEvent;
  windowEarliest: number;  // Relative to window start
  windowLatest: number;
  aggregated: boolean;     // Part of aggregate group
  groupId?: string;        // If aggregated
}

interface WindowPeriod {
  index: number;
  absolutePeriod: number;
  aggregationLevel: 'detailed' | 'aggregate';
  capacity: number;
}

class ProblemBuilder {
  async buildWindowProblem(params: {
    start: number;
    end: number;
    frozenDecisions: FrozenDecision[];
    aggregationLevel: AggregationLevel[];
  }): Promise<WindowProblem> {
    // Load events that could occur in window
    const candidateEvents = await this.loadCandidateEvents(
      params.start,
      params.end
    );

    // Apply frozen decisions
    const activeEvents = this.applyFrozenDecisions(
      candidateEvents,
      params.frozenDecisions
    );

    // Apply aggregation
    const windowEvents = this.applyAggregation(
      activeEvents,
      params.aggregationLevel
    );

    // Build periods with appropriate capacity
    const periods = this.buildPeriods(
      params.start,
      params.end,
      params.aggregationLevel
    );

    // Standard constraints
    const constraints = this.buildConstraints(windowEvents, periods);

    // Objective
    const objective = this.buildObjective(windowEvents, periods);

    return { events: windowEvents, periods, constraints, objective };
  }

  private applyAggregation(
    events: WindowEvent[],
    levels: AggregationLevel[]
  ): WindowEvent[] {
    const result: WindowEvent[] = [];

    for (const event of events) {
      const level = this.findAggregationLevel(event.windowEarliest, levels);

      if (level.level === 'detailed') {
        result.push(event);
      } else {
        // Aggregate: group events by asset and time block
        const groupId = this.getAggregateGroup(
          event,
          level.periodGrouping
        );
        result.push({
          ...event,
          aggregated: true,
          groupId
        });
      }
    }

    return result;
  }
}
```

### Schedule Merging

```typescript
interface ScheduleMerger {
  merge(
    existingSchedule: Schedule,
    windowSolution: WindowSolution,
    windowStart: number,
    frozenHorizon: number
  ): Schedule;
}

class ScheduleMergerImpl implements ScheduleMerger {
  merge(
    existing: Schedule,
    window: WindowSolution,
    windowStart: number,
    frozenHorizon: number
  ): Schedule {
    const merged: ScheduledEvent[] = [];

    // Keep frozen events from existing schedule
    const frozenEnd = windowStart + frozenHorizon;
    for (const event of existing.events) {
      if (event.scheduledPeriod < windowStart) {
        // Past events: keep as-is
        merged.push(event);
      } else if (event.scheduledPeriod < frozenEnd) {
        // Frozen but in window: keep existing decision
        merged.push(event);
      }
      // Events after frozen period: will be replaced
    }

    // Add new decisions from window solution
    for (const event of window.events) {
      if (event.scheduledPeriod >= frozenEnd) {
        merged.push({
          id: event.id,
          assetId: event.assetId,
          maintenanceTypeId: event.maintenanceTypeId,
          scheduledPeriod: event.scheduledPeriod,
          source: 'optimization',
          confidence: event.aggregated ? 'low' : 'high'
        });
      }
    }

    return {
      events: merged,
      metadata: {
        generatedAt: new Date(),
        windowStart,
        windowEnd: windowStart + window.windowSize,
        solverUsed: window.solverUsed
      }
    };
  }
}
```

## Aggregation Strategies

### Temporal Aggregation

Reduce time granularity for distant periods:

```typescript
interface TemporalAggregation {
  strategy: 'Group weeks into months or quarters';

  implementation: {
    detailed: 'Weekly periods (0-13 weeks)';
    monthly: 'Monthly buckets (14-52 weeks)';
    quarterly: 'Quarterly buckets (53+ weeks)';
  };

  effect: {
    variableReduction: '4x for monthly, 13x for quarterly';
    constraintReduction: 'Proportional';
    solutionQuality: 'Slightly reduced in aggregate periods';
  };
}

function aggregatePeriods(
  periods: number[],
  strategy: AggregationStrategy
): AggregatedPeriod[] {
  const result: AggregatedPeriod[] = [];

  let currentGroup: number[] = [];
  let currentLevel = 'detailed';

  for (const period of periods) {
    const level = strategy.getLevelForPeriod(period);

    if (level !== currentLevel && currentGroup.length > 0) {
      result.push({
        periods: [...currentGroup],
        level: currentLevel,
        capacity: sumCapacity(currentGroup)
      });
      currentGroup = [];
    }

    currentGroup.push(period);
    currentLevel = level;
  }

  if (currentGroup.length > 0) {
    result.push({
      periods: currentGroup,
      level: currentLevel,
      capacity: sumCapacity(currentGroup)
    });
  }

  return result;
}
```

### Event Aggregation

Group similar events:

```typescript
interface EventAggregation {
  strategy: 'Group maintenance events by type and time block';

  grouping: {
    byAsset: false;  // Keep asset-specific in detailed
    byType: true;    // Group same maintenance types
    byTimeBlock: true;  // Within aggregate period
  };

  example: {
    detailed: '10 individual PM-A events';
    aggregated: '1 "10x PM-A" event with 10x resources';
  };
}

function aggregateEvents(
  events: MaintenanceEvent[],
  aggregatePeriods: AggregatedPeriod[]
): AggregatedEvent[] {
  const result: AggregatedEvent[] = [];

  // Group events by type and aggregate period
  const groups = new Map<string, MaintenanceEvent[]>();

  for (const event of events) {
    const aggPeriod = findAggregatePeriod(event.targetPeriod, aggregatePeriods);
    if (!aggPeriod) continue;

    const key = `${event.maintenanceTypeId}_${aggPeriod.id}`;
    if (!groups.has(key)) {
      groups.set(key, []);
    }
    groups.get(key)!.push(event);
  }

  // Create aggregated events
  for (const [key, groupEvents] of groups) {
    result.push({
      id: `agg_${key}`,
      originalEvents: groupEvents.map(e => e.id),
      count: groupEvents.length,
      totalManHours: sum(groupEvents.map(e => e.manHours)),
      totalDuration: max(groupEvents.map(e => e.duration)),
      aggregatePeriod: key.split('_')[1]
    });
  }

  return result;
}
```

## Handling Changes

### Change Detection

```typescript
interface ChangeDetector {
  detectSignificantChanges(
    currentState: FleetState,
    previousState: FleetState
  ): ScheduleChange[];
}

interface ScheduleChange {
  type: 'mileage_deviation' | 'asset_added' | 'asset_removed' |
        'maintenance_completed' | 'maintenance_failed';
  assetId: string;
  severity: 'low' | 'medium' | 'high';
  details: object;
}

class ChangeDetectorImpl implements ChangeDetector {
  detectSignificantChanges(
    current: FleetState,
    previous: FleetState
  ): ScheduleChange[] {
    const changes: ScheduleChange[] = [];

    // Check mileage deviations
    for (const asset of current.assets) {
      const prev = previous.assets.find(a => a.id === asset.id);
      if (!prev) {
        changes.push({
          type: 'asset_added',
          assetId: asset.id,
          severity: 'high',
          details: { asset }
        });
        continue;
      }

      const drift = asset.actualMileage - asset.plannedMileage;
      const driftPercent = Math.abs(drift) / asset.plannedMileage;

      if (driftPercent > 0.1) {  // 10% deviation
        changes.push({
          type: 'mileage_deviation',
          assetId: asset.id,
          severity: driftPercent > 0.2 ? 'high' : 'medium',
          details: { drift, driftPercent }
        });
      }
    }

    return changes;
  }
}
```

### Re-planning Trigger

```typescript
interface ReplanningTrigger {
  shouldReplan(changes: ScheduleChange[]): boolean;
  getReplanScope(changes: ScheduleChange[]): ReplanScope;
}

interface ReplanScope {
  type: 'full' | 'partial' | 'none';
  affectedAssets?: string[];
  startPeriod: number;
}

class ReplanningTriggerImpl implements ReplanningTrigger {
  shouldReplan(changes: ScheduleChange[]): boolean {
    // Replan if any high severity changes
    if (changes.some(c => c.severity === 'high')) {
      return true;
    }

    // Replan if many medium severity changes
    const mediumCount = changes.filter(c => c.severity === 'medium').length;
    return mediumCount >= 5;
  }

  getReplanScope(changes: ScheduleChange[]): ReplanScope {
    const highSeverity = changes.filter(c => c.severity === 'high');

    if (highSeverity.length > 5) {
      return { type: 'full', startPeriod: getCurrentPeriod() };
    }

    if (highSeverity.length > 0) {
      return {
        type: 'partial',
        affectedAssets: highSeverity.map(c => c.assetId),
        startPeriod: getCurrentPeriod()
      };
    }

    return { type: 'none', startPeriod: 0 };
  }
}
```

## Performance Characteristics

### Typical Solve Times

```typescript
interface RollingHorizonPerformance {
  windowSize52Weeks: {
    events: '~500 in window';
    solveTime: '5-30 seconds';
    quality: 'Near-optimal for flexible period';
  };

  windowSize104Weeks: {
    events: '~1000 in window';
    solveTime: '30-120 seconds';
    quality: 'Good with aggregation';
  };

  fullHorizon10Years: {
    approach: 'Monthly rolling with quarterly aggregation';
    totalTime: '~10 minutes for complete horizon';
    quality: 'Good near-term, indicative long-term';
  };
}
```

